const productImageExtensions = new Set(["jpg", "jpeg", "png", "webp"]);
const productImageMimeTypes = new Set(["image/jpeg", "image/png", "image/webp"]);

function validateProductImageFile(file: File) {
  const validation = validateUploadFile(file);
  if (!validation.ok) return validation;
  const extension = file.name.split(".").pop()?.toLowerCase() ?? "";
  if (!productImageMimeTypes.has(file.type) && !productImageExtensions.has(extension)) {
    return { ok: false, message: "상품 이미지는 JPG, PNG, WebP 파일만 등록할 수 있습니다." };
  }
  return { ok: true, message: "" };
}

function withTimeout<T>(promise: Promise<T>, timeoutMs: number, message: string) {
  return new Promise<T>((resolve, reject) => {
    const timeoutId = window.setTimeout(() => reject(new Error(message)), timeoutMs);
    promise.then(
      (value) => {
        window.clearTimeout(timeoutId);
        resolve(value);
      },
      (error) => {
        window.clearTimeout(timeoutId);
        reject(error);
      },
    );
  });
}

function readFileAsDataUrl(file: File) {
  return new Promise<string>((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => resolve(String(reader.result || ""));
    reader.onerror = () => reject(reader.error ?? new Error("파일을 읽을 수 없습니다."));
    reader.readAsDataURL(file);
  });
}

async function createLocalProductImageUrl(file: File) {
  const objectUrl = URL.createObjectURL(file);
  try {
    const image = new Image();
    image.src = objectUrl;
    await withTimeout(image.decode(), 4000, "이미지 준비 시간이 길어 로컬 파일로 저장합니다.");
    const maxSize = 900;
    const scale = Math.min(1, maxSize / Math.max(image.naturalWidth, image.naturalHeight));
    const width = Math.max(1, Math.round(image.naturalWidth * scale));
    const height = Math.max(1, Math.round(image.naturalHeight * scale));
    const canvas = document.createElement("canvas");
    canvas.width = width;
    canvas.height = height;
    const context = canvas.getContext("2d");
    if (!context) return readFileAsDataUrl(file);
    context.fillStyle = "#ffffff";
    context.fillRect(0, 0, width, height);
    context.drawImage(image, 0, 0, width, height);
    return canvas.toDataURL("image/jpeg", 0.78);
  } catch {
    return readFileAsDataUrl(file);
  } finally {
    URL.revokeObjectURL(objectUrl);
  }
}

function useImageFallback(event: SyntheticEvent<HTMLImageElement>) {
  const image = event.currentTarget;
  if (image.dataset.fallbackApplied) return;
  image.dataset.fallbackApplied = "true";
  image.src = "/icon.png";
}

function productSaveErrorMessage(error: unknown) {
  if (error instanceof DOMException && error.name === "QuotaExceededError") {
    return "이미지 용량이 커서 앱 저장공간이 부족합니다. 더 작은 JPG 이미지로 다시 등록해 주세요.";
  }
  if (error instanceof Error && /quota|storage/i.test(error.message)) {
    return "이미지 저장공간이 부족하거나 브라우저 저장소에 접근할 수 없습니다. 더 작은 이미지로 다시 시도해 주세요.";
  }
  return error instanceof Error ? error.message : "상품 이미지 저장 중 오류가 발생했습니다.";
}

function ProductThumb({ product }: { product: SupplierProduct }) {
  return (
    <div className="productThumb" aria-hidden="true">
      <img src={product.main_image_url || "/icon.png"} alt="" loading="lazy" onError={useImageFallback} />
    </div>
  );
}

function ProductCard({
  data,
  product,
  favorite = false,
  onOpen,
  onFavorite,
}: {
  data: AppData;
  product: SupplierProduct;
  favorite?: boolean;
  onOpen: () => void;
  onFavorite?: () => void;
}) {
  const supplier = data.supplier_profiles.find((entry) => entry.id === product.supplier_id);
  const categoryName = getProductCategoryName(data, product.category_id);

  return (
    <article className="productCard">
      <button className="productThumbButton" type="button" onClick={onOpen} aria-label={`${product.title} 상세 보기`}>
        <ProductThumb product={product} />
      </button>
      <div className="productCardBody">
        <div>
          <span className="eyebrow">{categoryName}</span>
          <h2>{product.title}</h2>
          <p>{product.short_description || supplier?.business_name || "공급업체 상품"}</p>
        </div>
        <strong className="productPrice">{getSupplierProductPriceLabel(product)}</strong>
        <div className="chipLine">
          <StatusBadge tone={stockStatusTone(product.stock_status)}>{productStockStatusLabels[product.stock_status]}</StatusBadge>
          <span className="chip">{supplier?.business_name ?? "공급업체"}</span>
          <span className="chip">최소 {product.min_order_quantity}{product.unit_label}</span>
        </div>
        <div className="productCardActions">
          {onFavorite && (
            <button className={favorite ? "secondaryButton compact" : "ghostButton compact"} type="button" onClick={onFavorite}>
              {favorite ? "저장됨" : "저장"}
            </button>
          )}
          <button className="primaryButton compact" type="button" onClick={onOpen}>상세 보기</button>
        </div>
      </div>
    </article>
  );
}

function stockStatusTone(status: ProductStockStatus): "orange" | "blue" | "green" | "gray" {
  if (status === "in_stock") return "green";
  if (status === "low_stock") return "orange";
  if (status === "made_to_order") return "blue";
  return "gray";
}

function productApprovalTone(status: SupplierProduct["approval_status"]): "orange" | "blue" | "green" | "gray" {
  if (status === "approved") return "green";
  if (status === "pending") return "orange";
  if (status === "draft") return "blue";
  return "gray";
}

function defaultProductDraft(data: AppData, supplier: SupplierProfile): SupplierProductDraft {
  const category = data.product_categories.find((entry) => supplier.categories.includes(entry.name) && entry.is_active)
    ?? data.product_categories.find((entry) => entry.is_active)
    ?? data.product_categories[0];
  return {
    title: "",
    category_id: category?.id ?? "",
    short_description: "",
    description: "",
    main_image_url: "/icon.png",
    sku: "",
    brand: "",
    origin: "",
    unit_label: "개",
    package_unit: "",
    min_order_quantity: 1,
    price_type: "quote_only",
    price: 0,
    from_price: 0,
    vat_included: true,
    delivery_fee_type: "quote",
    delivery_fee_amount: 0,
    available_regions: supplier.service_regions.slice(0, 3),
    tax_invoice_available: supplier.tax_invoice_available,
    card_payment_available: supplier.card_payment_available,
    safe_trade_available: true,
    stock_status: "in_stock",
    lead_time_text: "평일 기준 1-2일",
    is_featured: false,
    is_public: supplier.approval_status === "approved",
    approval_status: "draft",
  };
}

function productToDraft(product: SupplierProduct): SupplierProductDraft {
  return {
    title: product.title,
    category_id: product.category_id,
    short_description: product.short_description,
    description: product.description,
    main_image_url: product.main_image_url,
    sku: product.sku,
    brand: product.brand,
    origin: product.origin,
    unit_label: product.unit_label,
    package_unit: product.package_unit,
    min_order_quantity: product.min_order_quantity,
    price_type: product.price_type,
    price: product.price,
    from_price: product.from_price,
    vat_included: product.vat_included,
    delivery_fee_type: product.delivery_fee_type,
    delivery_fee_amount: product.delivery_fee_amount,
    available_regions: product.available_regions,
    tax_invoice_available: product.tax_invoice_available,
    card_payment_available: product.card_payment_available,
    safe_trade_available: product.safe_trade_available,
    stock_status: product.stock_status,
    lead_time_text: product.lead_time_text,
    is_featured: product.is_featured,
    is_public: product.is_public,
    approval_status: product.approval_status,
  };
}

function ProductsPage({ data, navigate, setData, authSession }: MutatingPageProps & { authSession?: AppAuthSession | null }) {
  const buyerId = authSession?.role === "buyer" ? authSession.id : "buyer-1";
  const [keyword, setKeyword] = useState("");
  const [categoryId, setCategoryId] = useState("all");
  const [region, setRegion] = useState("all");
  const [favoritesOnly, setFavoritesOnly] = useState(false);
  const products = getVisibleSupplierProducts(data);
  const filtered = products.filter((product) => {
    const supplier = data.supplier_profiles.find((entry) => entry.id === product.supplier_id);
    const categoryName = getProductCategoryName(data, product.category_id);
    const haystack = `${product.title} ${product.short_description} ${product.brand} ${supplier?.business_name ?? ""} ${categoryName}`.toLowerCase();
    const keywordOk = !keyword.trim() || haystack.includes(keyword.trim().toLowerCase());
    const categoryOk = categoryId === "all" || product.category_id === categoryId;
    const regionOk = region === "all" || product.available_regions.some((entry) => entry.includes(region) || region.includes(entry.split(" ")[0]));
    const favoriteOk = !favoritesOnly || data.product_favorites.some((entry) => entry.product_id === product.id && entry.buyer_id === buyerId);
    return keywordOk && categoryOk && regionOk && favoriteOk;
  });
  const featured = filtered.filter((product) => product.is_featured).length;
  const quoteOnly = filtered.filter((product) => product.price_type === "quote_only").length;
  const registeredProducts = data.supplier_products.filter((product) => !product.deleted_at);
  const pendingProducts = registeredProducts.filter((product) => product.approval_status !== "approved" || !product.is_public).length;
  const productEmptyTitle = products.length === 0 && pendingProducts > 0 ? "공개 준비 중인 상품이 있습니다." : "조건에 맞는 상품이 없습니다.";
  const productEmptyDesc = products.length === 0 && pendingProducts > 0
    ? "공급업체가 등록한 상품은 관리자 검토와 공개 설정이 끝난 뒤 구매자에게 표시됩니다."
    : "검색어를 줄이거나 지역 조건을 전체로 바꿔보세요.";

  return (
    <Page>
      <PageTitle eyebrow="업체 상품" title="자주 쓰는 자재를 빠르게 찾아보세요." desc="공급업체가 공개한 상품을 보고 문의, 견적담기, 주문요청으로 이어갈 수 있습니다." />
      <div className="dashboardGrid">
        <Metric label="공개 상품" value={`${products.length}개`} icon={<Boxes />} />
        <Metric label="추천 상품" value={`${featured}개`} icon={<BadgeCheck />} />
        <Metric label="견적 문의 상품" value={`${quoteOnly}개`} icon={<ClipboardList />} />
        <Metric label="저장한 상품" value={`${data.product_favorites.filter((entry) => entry.buyer_id === buyerId).length}개`} icon={<PackageCheck />} />
      </div>

      <section className="filterPanel productFilterPanel">
        <Field label="검색">
          <input value={keyword} onChange={(event) => setKeyword(event.target.value)} placeholder="상품명, 업체명, 카테고리" />
        </Field>
        <Field label="카테고리">
          <select value={categoryId} onChange={(event) => setCategoryId(event.target.value)}>
            <option value="all">전체</option>
            {data.product_categories.filter((entry) => entry.is_active).map((category) => <option value={category.id} key={category.id}>{category.name}</option>)}
          </select>
        </Field>
        <Field label="납품지역">
          <select value={region} onChange={(event) => setRegion(event.target.value)}>
            <option value="all">전체</option>
            {commonServiceRegions.map((entry) => <option value={entry} key={entry}>{entry}</option>)}
          </select>
        </Field>
        <Toggle checked={favoritesOnly} label="저장한 상품만" onChange={setFavoritesOnly} />
      </section>

      {filtered.length ? (
        <section className="productGrid" aria-label="상품 목록">
          {filtered.map((product) => (
            <ProductCard
              key={product.id}
              data={data}
              product={product}
              favorite={data.product_favorites.some((entry) => entry.product_id === product.id && entry.buyer_id === buyerId)}
              onOpen={() => navigate(`/app/products/${product.id}`)}
              onFavorite={() => setData(toggleProductFavorite(data, product.id, buyerId))}
            />
          ))}
        </section>
      ) : (
        <EmptyState icon={<SearchCheck />} title={productEmptyTitle} desc={productEmptyDesc} />
      )}
    </Page>
  );
}

function ProductDetailPage({ data, navigate, setData, productId, authSession }: MutatingPageProps & { productId: string; authSession?: AppAuthSession | null }) {
  const product = data.supplier_products.find((entry) => entry.id === productId);
  if (!product || product.deleted_at || product.approval_status !== "approved" || !product.is_public) return <NotFound navigate={navigate} />;
  const supplier = data.supplier_profiles.find((entry) => entry.id === product.supplier_id);
  const categoryName = getProductCategoryName(data, product.category_id);
  const buyerId = authSession?.role === "buyer" ? authSession.id : "buyer-1";
  const favorite = data.product_favorites.some((entry) => entry.product_id === product.id && entry.buyer_id === buyerId);
  const relatedProducts = getVisibleSupplierProducts(data).filter((entry) => entry.supplier_id === product.supplier_id && entry.id !== product.id).slice(0, 3);
  return (
    <Page>
      <BackButton onClick={() => navigate("/app/products")} label="상품 목록" />
      <section className="productDetailHero">
        <div className="productImageFrame">
          <img src={product.main_image_url || "/icon.png"} alt="" onError={useImageFallback} />
        </div>
        <div className="productDetailCopy">
          <span className="eyebrow">{categoryName} · {supplier?.business_name ?? "공급업체"}</span>
          <h1>{product.title}</h1>
          <p>{product.short_description}</p>
          <strong>{getSupplierProductPriceLabel(product)}</strong>
          <div className="chipLine">
            <StatusBadge tone={stockStatusTone(product.stock_status)}>{productStockStatusLabels[product.stock_status]}</StatusBadge>
            <span className="chip">{product.package_unit || product.unit_label}</span>
            <span className="chip">최소 {product.min_order_quantity}{product.unit_label}</span>
            {product.tax_invoice_available && <span className="chip">세금계산서 가능</span>}
            {product.card_payment_available && <span className="chip">카드 가능</span>}
          </div>
          <div className="formActions">
            <button className="ghostButton" type="button" onClick={() => setData(toggleProductFavorite(data, product.id, buyerId))}>{favorite ? "저장 해제" : "자주 쓰는 상품 저장"}</button>
            <button className="secondaryButton" type="button" onClick={() => navigate(`/app/suppliers/${product.supplier_id}/store`)}>업체 상품관 보기</button>
          </div>
        </div>
      </section>

      <section className="productDetailGrid">
        <article className="formStack">
          <SectionHeader title="상품 정보" />
          <p className="mutedText">{product.description || "상세 설명은 공급업체 문의로 확인할 수 있습니다."}</p>
          <InfoPanel title="납품 조건" items={[
            `가능 지역: ${product.available_regions.join(", ") || "문의 필요"}`,
            `납품 소요: ${product.lead_time_text || "문의 필요"}`,
            `배송비: ${productDeliveryFeeTypeLabels[product.delivery_fee_type]}${product.delivery_fee_amount ? ` · ${money(product.delivery_fee_amount)}` : ""}`,
            `부가세: ${product.vat_included ? "포함" : "별도"}`,
          ]} />
          <InfoPanel title="거래 가능" items={[
            `세금계산서 ${yesNo(product.tax_invoice_available)}`,
            `카드결제 ${yesNo(product.card_payment_available)}`,
            `안심거래 ${yesNo(product.safe_trade_available)}`,
          ]} />
        </article>
        <ProductActionPanel data={data} product={product} navigate={navigate} setData={setData} authSession={authSession} />
      </section>

      <SectionHeader title="이 업체의 다른 상품" action="상품관 보기" onAction={() => navigate(`/app/suppliers/${product.supplier_id}/store`)} />
      {relatedProducts.length ? (
        <section className="productGrid compactProductGrid">
          {relatedProducts.map((entry) => <ProductCard key={entry.id} data={data} product={entry} onOpen={() => navigate(`/app/products/${entry.id}`)} />)}
        </section>
      ) : (
        <EmptyState icon={<Boxes />} title="아직 공개된 다른 상품이 없습니다." desc="상품 문의로 필요한 품목을 직접 요청할 수 있습니다." variant="compact" />
      )}
    </Page>
  );
}

function ProductActionPanel({ data, product, navigate, setData, authSession }: MutatingPageProps & { product: SupplierProduct; authSession?: AppAuthSession | null }) {
  const buyerId = authSession?.role === "buyer" ? authSession.id : "buyer-1";
  const [quantity, setQuantity] = useState(Math.max(product.min_order_quantity, 1));
  const [region, setRegion] = useState(product.available_regions[0] ?? commonServiceRegions[0] ?? "");
  const [date, setDate] = useState("2026-07-10");
  const [memo, setMemo] = useState("");
  const [doneMessage, setDoneMessage] = useState("");

  function submitInquiry(type: ProductInquiryDraft["inquiry_type"]) {
    const result = createProductInquiry(data, product.id, buyerId, {
      inquiry_type: type,
      message: memo || (type === "question" ? "상품 조건을 문의합니다." : "이 상품 기준으로 견적을 받고 싶습니다."),
      quantity,
      desired_delivery_date: date,
      delivery_region: region,
    });
    setData(result.data);
    if (result.threadId) navigate(`/app/chats/${result.threadId}`);
  }

  function requestQuote() {
    const result = createQuoteRequestFromProduct(data, product.id, buyerId, quantity, region, date, memo);
    setData(result.data);
    if (result.requestId) navigate(`/app/requests/${result.requestId}`);
  }

  function requestOrder() {
    const result = createProductOrderRequest(data, product.id, buyerId, { quantity, desired_delivery_date: date, delivery_region: region, buyer_memo: memo });
    setData(result.data);
    setDoneMessage(result.orderRequestId ? "주문요청이 공급업체에 전달되었습니다." : "주문요청을 처리하지 못했습니다.");
  }

  return (
    <aside className="productActionPanel">
      <SectionHeader title="문의/요청" />
      <Field label="수량">
        <input type="number" min={1} value={quantity} onChange={(event) => setQuantity(Math.max(1, Number(event.target.value) || 1))} />
      </Field>
      <Field label="납품지역">
        <select value={region} onChange={(event) => setRegion(event.target.value)}>
          {Array.from(new Set([...product.available_regions, ...commonServiceRegions])).filter(Boolean).map((entry) => <option value={entry} key={entry}>{entry}</option>)}
        </select>
      </Field>
      <Field label="희망 납품일">
        <input type="date" value={date} onChange={(event) => setDate(event.target.value)} />
      </Field>
      <Field label="메모">
        <textarea value={memo} onChange={(event) => setMemo(event.target.value)} placeholder="수량, 납품 시간, 세금계산서 요청 등을 적어주세요." />
      </Field>
      <div className="productActionButtons">
        <button className="secondaryButton" type="button" onClick={() => submitInquiry("question")}>문의하기</button>
        <button className="primaryButton" type="button" onClick={requestQuote}>견적에 담기</button>
        <button className="ghostButton" type="button" onClick={requestOrder}>주문요청</button>
      </div>
      {doneMessage && <p className="successText">{doneMessage}</p>}
      <button className="ghostButton dangerButton" type="button" onClick={() => setData(createProductReport(data, product.id, buyerId, "wrong_info", "구매자 화면에서 상품 정보 검토 요청"))}>상품 정보 신고</button>
    </aside>
  );
}

function SupplierStorePage({ data, navigate, setData, supplierId, editable = false }: MutatingPageProps & { supplierId: string; editable?: boolean }) {
  const supplier = data.supplier_profiles.find((entry) => entry.id === supplierId);
  if (!supplier) return <NotFound navigate={navigate} />;
  const store = getSupplierStoreProfile(data, supplier.id);
  const products = getVisibleSupplierProducts(data).filter((product) => product.supplier_id === supplier.id);
  const stats = supplierStatsFor(data, supplier.id);
  return (
    <Page>
      <BackButton onClick={() => navigate(editable ? "/app/supplier/products" : "/app/products")} label={editable ? "내 상품" : "상품 목록"} />
      <section className="supplierStoreHero">
        <div>
          <span className="eyebrow">공급업체 상품관</span>
          <h1>{store?.store_name ?? `${supplier.business_name} 상품관`}</h1>
          <p>{store?.store_description ?? supplier.description ?? "공급업체가 등록한 상품을 확인하세요."}</p>
          <div className="chipLine">
            {supplier.tax_invoice_available && <span className="chip">세금계산서 가능</span>}
            {supplier.card_payment_available && <span className="chip">카드 가능</span>}
            <span className="chip">응답률 {stats.response_rate}%</span>
          </div>
        </div>
        <div className="supplierRatingBlock">
          <strong>{products.length}</strong>
          <span>공개 상품</span>
        </div>
      </section>
      <section className="twoColumn">
        <InfoPanel title="주요 카테고리" items={store?.main_categories.length ? store.main_categories : supplier.categories} />
        <InfoPanel title="납품 가능 지역" items={store?.delivery_regions.length ? store.delivery_regions : supplier.service_regions} />
        <InfoPanel title="운영 안내" items={[store?.business_hours_text ?? "영업시간 문의", store?.contact_policy_text ?? "싸와 문의로 조건 확인"]} />
      </section>
      <SectionHeader title="상품 목록" action={editable ? "상품 등록" : undefined} onAction={editable ? () => navigate("/app/supplier/products/new") : undefined} />
      {products.length ? (
        <section className="productGrid">
          {products.map((product) => <ProductCard key={product.id} data={data} product={product} onOpen={() => navigate(`/app/products/${product.id}`)} />)}
        </section>
      ) : (
        <EmptyState icon={<Boxes />} title="공개된 상품이 없습니다." desc="공급업체가 상품 공개를 완료하면 이곳에 표시됩니다." />
      )}
    </Page>
  );
}

function SupplierProductsPage({ data, navigate, setData }: MutatingPageProps) {
  const supplier = getActiveSupplier(data);
  const products = getSupplierProducts(data, supplier.id);
  const summary = getSupplierProductSummary(data, supplier.id);
  const [keyword, setKeyword] = useState("");
  const [visibility, setVisibility] = useState("all");
  const [approvalStatus, setApprovalStatus] = useState("all");
  const [sort, setSort] = useState("updated");
  const recentInquiries = data.product_inquiries.filter((entry) => entry.supplier_id === supplier.id && entry.created_at >= "2026-06-10");
  const pendingInquiries = data.product_inquiries.filter((entry) => entry.supplier_id === supplier.id && entry.status === "pending");
  const filteredProducts = products
    .filter((product) => {
      const searchText = `${product.title} ${product.short_description} ${product.description} ${product.sku} ${product.brand} ${getProductCategoryName(data, product.category_id)}`.toLowerCase();
      const keywordOk = !keyword.trim() || searchText.includes(keyword.trim().toLowerCase());
      const visibilityOk = visibility === "all"
        || (visibility === "public" && product.is_public && product.approval_status === "approved")
        || (visibility === "private" && (!product.is_public || product.approval_status === "hidden"));
      const statusOk = approvalStatus === "all" || product.approval_status === approvalStatus;
      return keywordOk && visibilityOk && statusOk;
    })
    .sort((a, b) => {
      if (sort === "inquiries") return (b.inquiry_count + b.order_request_count) - (a.inquiry_count + a.order_request_count);
      if (sort === "price") return (b.price || b.from_price) - (a.price || a.from_price);
      return b.updated_at.localeCompare(a.updated_at);
    });

  function productStatusActionLabel(product: SupplierProduct) {
    if (product.is_public && product.approval_status === "approved") return "비공개";
    if (product.approval_status === "pending") return "검토중";
    return "공개하기";
  }

  function toggleProductPublic(product: SupplierProduct) {
    if (product.approval_status === "pending") return;
    setData(updateSupplierProduct(data, product.id, { is_public: !product.is_public, approval_status: product.is_public ? "draft" : "pending" }));
  }

  return (
    <Page>
      <div className="supplierProductsPage">
      <div className="supplierProductsHeader">
        <div>
          <span className="eyebrow">내 상품</span>
          <h1>상품 등록 및 관리</h1>
          <p>상품을 등록하고 공개하여 더 많은 바이어에게 노출하세요. 문의 및 주문 현황을 한눈에 관리할 수 있습니다.</p>
        </div>
        <div className="supplierProductsControls" aria-label="상품 검색과 필터">
          <div className="productSearchBox">
            <input value={keyword} onChange={(event) => setKeyword(event.target.value)} placeholder="상품명으로 검색" />
            <SearchCheck size={18} />
          </div>
          <select value={visibility} onChange={(event) => setVisibility(event.target.value)} aria-label="공개 상태">
            <option value="all">전체</option>
            <option value="public">공개</option>
            <option value="private">비공개</option>
          </select>
          <select value={approvalStatus} onChange={(event) => setApprovalStatus(event.target.value)} aria-label="검토 상태">
            <option value="all">상태 전체</option>
            <option value="approved">공개 승인</option>
            <option value="pending">검토 중</option>
            <option value="draft">임시저장</option>
            <option value="rejected">반려</option>
          </select>
        </div>
      </div>
      <SupplierStatusNotice supplier={supplier} navigate={navigate} />
      <div className="supplierProductStats">
        <Metric label="전체 상품" value={`${summary.total}개`} desc="등록된 상품 수" icon={<Boxes />} />
        <Metric label="공개 상품" value={`${summary.publicCount}개`} desc="공개 승인된 상품" icon={<BadgeCheck />} />
        <Metric label="검토 중" value={`${summary.pendingCount}개`} desc="검토 대기 상품" icon={<ShieldCheck />} />
        <Metric label="문의/주문" value={`${recentInquiries.length + summary.orderRequestCount}건`} desc="최근 30일 기준" icon={<MessageCircle />} />
      </div>

      <section className="supplierProductGuide">
        <div className="supplierProductGuideIntro">
          <div className="guideIllustration"><Boxes size={34} /></div>
          <div>
            <strong>처음 등록도 3분이면 가능합니다.</strong>
            <span>아래 3단계만 따라하면 손쉽게 등록해요.</span>
          </div>
        </div>
        <div className="supplierProductSteps">
          <div><b>1</b><strong>기본 정보 입력</strong><span>상품명, 이미지, 설명</span></div>
          <ArrowRight size={18} />
          <div><b>2</b><strong>가격/옵션 설정</strong><span>가격, 단위, 옵션 추가</span></div>
          <ArrowRight size={18} />
          <div><b>3</b><strong>공개 요청</strong><span>검토 후 공개 승인</span></div>
        </div>
      </section>

      <section className="supplierProductListHeader">
        <h2>내 상품 목록</h2>
        <div>
          <button className="primaryButton compact" type="button" onClick={() => navigate("/app/supplier/products/new")}><Plus size={16} /> 상품 등록</button>
          <button className="secondaryButton compact" type="button" onClick={() => navigate("/app/supplier/store")}>상품관 보기</button>
          <select value={sort} onChange={(event) => setSort(event.target.value)} aria-label="상품 정렬">
            <option value="updated">최신 등록순</option>
            <option value="inquiries">문의 많은순</option>
            <option value="price">높은 가격순</option>
          </select>
        </div>
      </section>

      {filteredProducts.length ? (
        <section className="supplierProductList upgraded">
          {filteredProducts.map((product) => (
            <article className="supplierProductRow" key={product.id}>
              <ProductThumb product={product} />
              <div className="supplierProductMainInfo">
                <strong>{product.title}</strong>
                <p>{product.short_description || getProductCategoryName(data, product.category_id)}</p>
              </div>
              <StatusBadge tone={productApprovalTone(product.approval_status)}>{productApprovalStatusLabels[product.approval_status]}</StatusBadge>
              <strong className="supplierProductPrice">{getSupplierProductPriceLabel(product)}</strong>
              <span className="supplierProductCount"><MessageCircle size={16} /> 문의 {product.inquiry_count}</span>
              <span className="supplierProductCount"><PackageCheck size={16} /> 주문 {product.order_request_count}</span>
              <div className="rowActions">
                <button className="secondaryButton compact" type="button" onClick={() => navigate(`/app/supplier/products/${product.id}/edit`)}>수정</button>
                <button className="ghostButton compact" type="button" disabled={product.approval_status === "pending"} onClick={() => toggleProductPublic(product)}>{productStatusActionLabel(product)}</button>
                <button className="ghostButton compact dangerButton" type="button" onClick={() => setData(deleteSupplierProduct(data, product.id))}>삭제</button>
              </div>
            </article>
          ))}
        </section>
      ) : (
        <EmptyState icon={<Boxes />} title="조건에 맞는 상품이 없습니다." desc="검색어 또는 필터를 줄이면 등록한 상품을 다시 확인할 수 있습니다." actionLabel="상품 등록" onAction={() => navigate("/app/supplier/products/new")} />
      )}
      {pendingInquiries.length > 0 && <p className="supplierProductFootnote">답변 대기 문의 {pendingInquiries.length}건이 있습니다. 문의 메뉴에서 빠르게 답변해 주세요.</p>}
      </div>
    </Page>
  );
}

function SupplierProductFormPage({ data, navigate, setData, productId }: MutatingPageProps & { productId?: string }) {
  const supplier = getActiveSupplier(data);
  const existing = productId ? data.supplier_products.find((entry) => entry.id === productId && entry.supplier_id === supplier.id) : undefined;
  const [draft, setDraft] = useState<SupplierProductDraft>(() => existing ? productToDraft(existing) : defaultProductDraft(data, supplier));
  const [productImageFile, setProductImageFile] = useState<File | null>(null);
  const [productImagePreview, setProductImagePreview] = useState(draft.main_image_url || "/icon.png");
  const [imageNotice, setImageNotice] = useState("");
  const [isSaving, setIsSaving] = useState(false);
  const [savingStep, setSavingStep] = useState("");
  const [saveWarning, setSaveWarning] = useState("");
  const [error, setError] = useState("");

  useEffect(() => {
    if (!productImageFile) setProductImagePreview(draft.main_image_url || "/icon.png");
  }, [draft.main_image_url, productImageFile]);

  useEffect(() => {
    return () => {
      if (productImagePreview.startsWith("blob:")) URL.revokeObjectURL(productImagePreview);
    };
  }, [productImagePreview]);

  function update<K extends keyof SupplierProductDraft>(key: K, value: SupplierProductDraft[K]) {
    setDraft((current) => ({ ...current, [key]: value }));
  }

  function handleProductImageChange(event: ChangeEvent<HTMLInputElement>) {
    const file = event.currentTarget.files?.[0] ?? null;
    setError("");
    setImageNotice("");
    setSaveWarning("");
    if (!file) {
      setProductImageFile(null);
      return;
    }
    const validation = validateProductImageFile(file);
    if (!validation.ok) {
      event.currentTarget.value = "";
      setProductImageFile(null);
      setError(validation.message);
      return;
    }
    const previewUrl = URL.createObjectURL(file);
    setProductImageFile(file);
    setProductImagePreview(previewUrl);
    setImageNotice(`${file.name} 파일을 선택했습니다. 저장하면 상품 대표 이미지로 등록됩니다.`);
  }

  async function resolveProductImageUrl() {
    if (!productImageFile) return draft.main_image_url || "/icon.png";
    setSavingStep("상품 이미지를 앱에 맞게 준비하고 있습니다.");
    const localImageUrl = await createLocalProductImageUrl(productImageFile);
    setSavingStep("상품 이미지를 서버에 업로드하고 있습니다.");
    try {
      const uploadResult = await withTimeout(
        uploadAppFile("productImage", supplier.user_id, productImageFile),
        8000,
        "서버 업로드 응답이 늦어 앱 내부 저장으로 전환했습니다.",
      );
      if (uploadResult.ok) {
        setImageNotice("상품 이미지가 서버에 업로드되었습니다.");
        return uploadResult.publicUrl || localImageUrl;
      }
      setSaveWarning(`서버 업로드는 실패했지만 앱 안에는 이미지가 저장됩니다. (${uploadResult.message})`);
    } catch (uploadError) {
      setSaveWarning(uploadError instanceof Error ? uploadError.message : "서버 업로드에 실패해 앱 내부 저장으로 전환했습니다.");
    }
    return localImageUrl;
  }

  async function submit(event: FormEvent) {
    event.preventDefault();
    if (isSaving) return;
    setError("");
    setSaveWarning("");
    if (!draft.title.trim()) return setError("상품명을 입력해 주세요.");
    if (!draft.category_id) return setError("카테고리를 선택해 주세요.");
    if (!draft.unit_label.trim()) return setError("단위를 입력해 주세요.");
    if (!draft.available_regions.length) return setError("납품 가능 지역을 1개 이상 선택해 주세요.");
    setIsSaving(true);
    setSavingStep(productImageFile ? "상품 이미지 저장을 시작합니다." : "상품 정보를 저장하고 있습니다.");
    try {
      const mainImageUrl = await resolveProductImageUrl();
      setSavingStep(existing ? "수정한 상품 정보를 저장하고 있습니다." : "새 상품 정보를 등록하고 있습니다.");
      const nextDraft = {
        ...draft,
        main_image_url: mainImageUrl,
        is_public: supplier.approval_status === "approved" && draft.is_public,
      };
      if (existing) {
        const nextData = updateSupplierProduct(data, existing.id, {
          ...existing,
          ...nextDraft,
          main_image_url: nextDraft.main_image_url || "/icon.png",
        });
        setData(nextData);
        navigate("/app/supplier/products");
        return;
      }
      const result = createSupplierProduct(data, supplier.id, nextDraft);
      setData(result.data);
      navigate("/app/supplier/products");
    } catch (submitError) {
      setError(productSaveErrorMessage(submitError));
    } finally {
      setIsSaving(false);
      setSavingStep("");
    }
  }

  return (
    <Page>
      <BackButton onClick={() => navigate("/app/supplier/products")} label="내 상품" />
      <PageTitle eyebrow="상품 등록" title={existing ? "상품 정보를 수정하세요." : "3분 안에 상품을 등록하세요."} desc="가격을 모르면 견적 문의로 등록할 수 있고, 공개 상품은 관리자 검토 후 구매자에게 노출됩니다." />
      {error && <div className="statusNotice warning"><strong>{error}</strong></div>}
      {saveWarning && !isSaving && <div className="statusNotice warning"><strong>{saveWarning}</strong></div>}
      <form className={isSaving ? "wizardShell productFormShell saving" : "wizardShell productFormShell"} onSubmit={submit} aria-busy={isSaving}>
        {isSaving && (
          <div className="productUploadOverlay" role="status" aria-live="polite">
            <span className="spinner large" />
            <strong>{productImageFile ? "상품 이미지를 등록하고 있습니다." : "상품 정보를 저장하고 있습니다."}</strong>
            <p>{savingStep || "잠시만 기다려 주세요. 완료되면 상품 목록으로 이동합니다."}</p>
            {productImageFile && <small>화면을 닫거나 뒤로 가지 말고 기다려 주세요.</small>}
          </div>
        )}
        <section className="wizardPanel">
          <SectionHeader title="1. 기본 정보" />
          <div className="formGrid">
            <Field label="상품명">
              <input value={draft.title} onChange={(event) => update("title", event.target.value)} placeholder="예: 배달 봉투 대형 1000장" />
            </Field>
            <Field label="카테고리">
              <select value={draft.category_id} onChange={(event) => update("category_id", event.target.value)}>
                {data.product_categories.filter((entry) => entry.is_active).map((category) => <option value={category.id} key={category.id}>{category.name}</option>)}
              </select>
            </Field>
            <Field label="대표 이미지">
              <div className="productImagePicker">
                <div className="productImagePreview">
                  <img src={productImagePreview || "/icon.png"} alt="상품 대표 이미지 미리보기" onError={useImageFallback} />
                </div>
                <input type="file" accept="image/jpeg,image/png,image/webp" onChange={handleProductImageChange} />
                {imageNotice && <small>{imageNotice}</small>}
              </div>
            </Field>
            <Field label="한 줄 설명">
              <input value={draft.short_description} onChange={(event) => update("short_description", event.target.value)} placeholder="구매자가 목록에서 바로 이해할 설명" />
            </Field>
          </div>
          <Field label="상세 설명">
            <textarea value={draft.description} onChange={(event) => update("description", event.target.value)} placeholder="규격, 사용처, 주의사항을 간단히 적어주세요." />
          </Field>
        </section>

        <section className="wizardPanel">
          <SectionHeader title="2. 가격과 수량" />
          <div className="formGrid">
            <Field label="가격 표시 방식">
              <select value={draft.price_type} onChange={(event) => update("price_type", event.target.value as SupplierProductDraft["price_type"])}>
                {Object.entries(productPriceTypeLabels).map(([key, label]) => <option value={key} key={key}>{label}</option>)}
              </select>
            </Field>
            <Field label="고정가">
              <input
                type="text"
                inputMode="numeric"
                value={draft.price_type === "fixed" ? formatMoneyInput(draft.price) : ""}
                onChange={(event) => update("price", parseMoneyInput(event.target.value))}
                disabled={draft.price_type !== "fixed"}
                placeholder="예: 34,000"
              />
            </Field>
            <Field label="시작가">
              <input
                type="text"
                inputMode="numeric"
                value={draft.price_type === "from_price" ? formatMoneyInput(draft.from_price) : ""}
                onChange={(event) => update("from_price", parseMoneyInput(event.target.value))}
                disabled={draft.price_type !== "from_price"}
                placeholder="예: 34,000"
              />
            </Field>
            <Field label="단위">
              <input value={draft.unit_label} onChange={(event) => update("unit_label", event.target.value)} placeholder="박스, 묶음, kg" />
            </Field>
            <Field label="포장 단위">
              <input value={draft.package_unit} onChange={(event) => update("package_unit", event.target.value)} placeholder="1000매, 15kg" />
            </Field>
            <Field label="최소 주문수량">
              <input type="number" min={1} value={draft.min_order_quantity} onChange={(event) => update("min_order_quantity", Number(event.target.value))} />
            </Field>
          </div>
          <div className="toggleGrid">
            <Toggle checked={draft.vat_included} label="부가세 포함" onChange={(value) => update("vat_included", value)} />
            <Toggle checked={draft.tax_invoice_available} label="세금계산서 가능" onChange={(value) => update("tax_invoice_available", value)} />
            <Toggle checked={draft.card_payment_available} label="카드결제 가능" onChange={(value) => update("card_payment_available", value)} />
            <Toggle checked={draft.safe_trade_available} label="안심거래 가능" onChange={(value) => update("safe_trade_available", value)} />
          </div>
        </section>

        <section className="wizardPanel">
          <SectionHeader title="3. 납품 조건과 공개" />
          <div className="formGrid">
            <Field label="재고 상태">
              <select value={draft.stock_status} onChange={(event) => update("stock_status", event.target.value as ProductStockStatus)}>
                {Object.entries(productStockStatusLabels).map(([key, label]) => <option value={key} key={key}>{label}</option>)}
              </select>
            </Field>
            <Field label="배송비">
              <select value={draft.delivery_fee_type} onChange={(event) => update("delivery_fee_type", event.target.value as SupplierProductDraft["delivery_fee_type"])}>
                {Object.entries(productDeliveryFeeTypeLabels).map(([key, label]) => <option value={key} key={key}>{label}</option>)}
              </select>
            </Field>
            <Field label="배송비 금액">
              <input
                type="text"
                inputMode="numeric"
                value={formatMoneyInput(draft.delivery_fee_amount)}
                onChange={(event) => update("delivery_fee_amount", parseMoneyInput(event.target.value))}
                placeholder="예: 3,000"
              />
            </Field>
            <Field label="납품 소요시간">
              <input value={draft.lead_time_text} onChange={(event) => update("lead_time_text", event.target.value)} placeholder="평일 기준 1-2일" />
            </Field>
          </div>
          <SupplierRegionSelector regions={draft.available_regions} onChange={(regions) => update("available_regions", regions)} />
          <div className="toggleGrid">
            <Toggle checked={draft.is_public} label="공개 요청" onChange={(value) => update("is_public", value)} />
            <Toggle checked={draft.is_featured} label="대표 상품으로 표시" onChange={(value) => update("is_featured", value)} />
          </div>
          {supplier.approval_status !== "approved" && <p className="mutedText">입점 승인 전에는 상품이 임시저장만 가능하며 구매자에게 공개되지 않습니다.</p>}
          <div className="formActions">
            <button className="secondaryButton" type="button" onClick={() => navigate("/app/supplier/products")}>취소</button>
            <button className="primaryButton" type="submit" disabled={isSaving}>{isSaving ? "저장 중" : existing ? "수정 저장" : "상품 등록"}</button>
          </div>
        </section>
      </form>
    </Page>
  );
}

function AdminProductsPage({ data, navigate, setData }: MutatingPageProps) {
  const [status, setStatus] = useState("all");
  const summary = getSupplierProductSummary(data);
  const products = data.supplier_products
    .filter((product) => !product.deleted_at)
    .filter((product) => status === "all" || product.approval_status === status)
    .sort((a, b) => b.updated_at.localeCompare(a.updated_at));
  const openReports = data.product_reports.filter((entry) => entry.status === "pending" || entry.status === "reviewing");
  return (
    <Page>
      <PageTitle eyebrow="상품 관리" title="공급업체 상품 공개 상태를 관리합니다." desc="승인 대기, 신고, 숨김 상품을 확인하고 구매자 노출을 제어합니다." />
      <div className="dashboardGrid">
        <Metric label="전체 상품" value={`${summary.total}개`} icon={<Boxes />} />
        <Metric label="승인 대기" value={`${summary.pendingCount}개`} icon={<ShieldCheck />} />
        <Metric label="공개 중" value={`${summary.publicCount}개`} icon={<BadgeCheck />} />
        <Metric label="열린 신고" value={`${openReports.length}건`} icon={<Bell />} />
      </div>
      <section className="filterPanel">
        <Field label="상태">
          <select value={status} onChange={(event) => setStatus(event.target.value)}>
            <option value="all">전체</option>
            {Object.entries(productApprovalStatusLabels).map(([key, label]) => <option value={key} key={key}>{label}</option>)}
          </select>
        </Field>
      </section>
      <div className="tableWrap">
        <table>
          <thead>
            <tr>
              <th>상품</th>
              <th>업체</th>
              <th>가격</th>
              <th>상태</th>
              <th>성과</th>
              <th>관리</th>
            </tr>
          </thead>
          <tbody>
            {products.map((product) => {
              const supplier = data.supplier_profiles.find((entry) => entry.id === product.supplier_id);
              return (
                <tr key={product.id}>
                  <td><strong>{product.title}</strong><br /><small>{getProductCategoryName(data, product.category_id)}</small></td>
                  <td>{supplier?.business_name ?? "공급업체"}</td>
                  <td>{getSupplierProductPriceLabel(product)}</td>
                  <td><StatusBadge tone={productApprovalTone(product.approval_status)}>{productApprovalStatusLabels[product.approval_status]}</StatusBadge></td>
                  <td>조회 {product.view_count} · 문의 {product.inquiry_count} · 주문 {product.order_request_count}</td>
                  <td>
                    <div className="rowActions">
                      <button className="secondaryButton compact" type="button" onClick={() => setData(updateProductApprovalStatus(data, product.id, "approved"))}>승인</button>
                      <button className="ghostButton compact" type="button" onClick={() => setData(updateProductApprovalStatus(data, product.id, "rejected", "상품 정보 보완이 필요합니다."))}>반려</button>
                      <button className="ghostButton compact dangerButton" type="button" onClick={() => setData(updateProductApprovalStatus(data, product.id, "hidden", "관리자 숨김 처리"))}>숨김</button>
                    </div>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>

      <SectionHeader title="상품 신고" />
      {openReports.length ? (
        <section className="reviewList">
          {openReports.map((report) => {
            const product = data.supplier_products.find((entry) => entry.id === report.product_id);
            return (
              <article className="reviewCard" key={report.id}>
                <div>
                  <strong>{product?.title ?? "상품"}</strong>
                  <p>{productReportReasonLabels[report.reason]} · {report.detail}</p>
                  <StatusBadge tone={report.status === "resolved" ? "green" : "orange"}>{productReportStatusLabels[report.status]}</StatusBadge>
                </div>
                <div className="rowActions">
                  <button className="secondaryButton compact" type="button" onClick={() => setData(updateProductReportStatus(data, report.id, "resolved", "처리 완료"))}>처리 완료</button>
                  <button className="ghostButton compact" type="button" onClick={() => setData(updateProductReportStatus(data, report.id, "dismissed", "문제 없음"))}>기각</button>
                </div>
              </article>
            );
          })}
        </section>
      ) : (
        <EmptyState icon={<Bell />} title="처리할 상품 신고가 없습니다." desc="구매자 신고가 접수되면 이곳에서 검토합니다." variant="compact" />
      )}
    </Page>
  );
}

function getTodayRecommendationFromUrl(data: AppData) {
  if (typeof window === "undefined") return null;
  const params = new URLSearchParams(window.location.search);
  if (params.get("source") !== "today") return null;
  const rawCategory = params.get("category")?.trim() ?? "";
  const rawItem = params.get("item")?.trim() ?? "";
  const label = rawItem || rawCategory || "비용이 오른 품목";
  const normalizedCategory = rawCategory.replace(/비$/, "");
  const matchedCategory = data.categories.find((category) =>
    category.name === rawCategory ||
    category.name === normalizedCategory ||
    rawCategory.includes(category.name) ||
    category.name.includes(normalizedCategory),
  ) ?? data.categories[0];
  return {
    label,
    categoryId: matchedCategory?.id ?? data.categories[0]?.id ?? "",
    title: `${label} 재견적 요청`,
    description: `오늘장사에서 ${label} 비용 확인이 필요해 추천된 견적요청입니다. 다른 업체 견적을 확인해보세요.`,
    textInput: `${label} 관련 품목 견적을 다시 받아보고 싶어요.`,
    items: [{ ...emptyItem, item_name: rawItem || label.replace(/비$/, ""), memo: "오늘장사 추천 항목" }],
  };
}

function parseTodayDraftItems(itemsJson: string): QuoteRequestDraft["items"] {
  try {
    const parsed = JSON.parse(itemsJson);
    if (!Array.isArray(parsed)) return [];
    return parsed.map((entry) => ({
      item_name: String(entry.item_name ?? entry.name ?? "").trim(),
      spec: String(entry.spec ?? ""),
      quantity: Number(entry.quantity) || 1,
      unit: String(entry.unit ?? "개"),
      memo: String(entry.memo ?? "수량과 규격을 확인해주세요."),
      is_required: entry.is_required ?? true,
      allow_alternative: entry.allow_alternative ?? true,
      confidence_score: Number(entry.confidence_score) || 82,
      needs_review: Boolean(entry.needs_review),
      review_reason: String(entry.review_reason ?? ""),
    })).filter((entry) => entry.item_name);
  } catch {
    return [];
  }
}

type PreviousPurchaseInfo = {
  date: string;
  supplierName: string;
  categoryName: string;
  quantity: number;
  unit: string;
  unitPrice: number;
  totalAmount: number;
};

function normalizePurchaseItemName(value: string) {
  return value.replace(/\s+/g, "").trim().toLowerCase();
}

function buildPreviousPurchaseLookup(data: AppData, buyerIds: Set<string>) {
  const recordsById = new Map<string, PurchaseRecord>();
  const activeBuyerIds = new Set(buyerIds);
  if (activeBuyerIds.size === 0) activeBuyerIds.add("buyer-1");

  data.purchase_records.forEach((record) => {
    if (record.deleted_at) return;
    if (!activeBuyerIds.has(record.buyer_id) && (!record.business_id || !activeBuyerIds.has(record.business_id))) return;
    recordsById.set(record.id, record);
  });

  const lookup = new Map<string, PreviousPurchaseInfo>();
  data.purchase_record_items.forEach((item) => {
    const record = recordsById.get(item.purchase_record_id);
    const key = normalizePurchaseItemName(item.item_name);
    if (!record || !key) return;
    const totalAmount = item.total_price || Math.round((item.unit_price || 0) * (item.quantity || 1)) || record.total_amount;
    const unitPrice = item.unit_price || (item.quantity ? Math.round(totalAmount / item.quantity) : totalAmount);
    const next: PreviousPurchaseInfo = {
      date: record.purchase_date,
      supplierName: record.supplier_name,
      categoryName: record.category_name,
      quantity: item.quantity,
      unit: item.unit,
      unitPrice,
      totalAmount,
    };
    const current = lookup.get(key);
    if (!current || current.date < next.date) lookup.set(key, next);
  });

  return lookup;
}

function findPreviousPurchaseForItem(lookup: Map<string, PreviousPurchaseInfo>, itemName: string) {
  const key = normalizePurchaseItemName(itemName);
  if (!key) return undefined;
  const exact = lookup.get(key);
  if (exact) return exact;
  for (const [historyKey, history] of lookup.entries()) {
    if (historyKey.includes(key) || key.includes(historyKey)) return history;
  }
  return undefined;
}

function NewRequestPage({ data, navigate, setData, routePath = "/app/requests/new", authSession }: MutatingPageProps & { routePath?: string; authSession?: AppAuthSession | null }) {
  const wizardSteps = ["올리기", "품목 확인", "납품 조건", "완료"];
  const searchParams = getSearchParams(routePath);
  const todayDraftId = searchParams.get("draftId") ?? "";
  const requestedInputMethod = parseRequestInputMethod(searchParams.get("method") ?? searchParams.get("inputMethod"));
  const buyerIdsForSession = useMemo(() => {
    const ids = getBuyerIdsForSession(data, authSession);
    if (authSession?.role === "buyer" && authSession.id) ids.add(authSession.id);
    if (ids.size === 0) ids.add("buyer-1");
    return ids;
  }, [data, authSession]);
  const todayRecommendation = todayDraftId ? null : getTodayRecommendationFromUrl(data);
  const todayDraft = todayDraftId
    ? Array.from(buyerIdsForSession)
      .map((buyerBusinessId) => getTodayQuoteDraft(data, todayDraftId, buyerBusinessId))
      .find((entry): entry is TodaySsawaQuoteDraft => Boolean(entry))
    : undefined;
  const todayDraftItems = todayDraft ? parseTodayDraftItems(todayDraft.items_json) : undefined;
  const todayDraftCategory = todayDraft ? data.categories.find((category) => category.name === todayDraft.category || todayDraft.category.includes(category.name) || category.name.includes(todayDraft.category)) : undefined;
  const [step, setStep] = useState(todayDraftId || requestedInputMethod ? 1 : 0);
  const [textInput, setTextInput] = useState(todayRecommendation?.textInput ?? todayDraft?.description ?? "치킨박스 1000개, 소스컵 2000개, 배달봉투 대형 1000장 필요해요.");
  const [receiptFileName, setReceiptFileName] = useState("");
  const [receiptImageFile, setReceiptImageFile] = useState<File | null>(null);
  const [receiptAnalysisPreview, setReceiptAnalysisPreview] = useState<ReceiptAnalysisPreview | null>(null);
  const [receiptAnalysisSource, setReceiptAnalysisSource] = useState<ReceiptAnalysisSource>("");
  const [receiptAnalysisNotice, setReceiptAnalysisNotice] = useState("");
  const [receiptAnalysisLoading, setReceiptAnalysisLoading] = useState(false);
  const [showMoreConditions, setShowMoreConditions] = useState(false);
  const [draft, setDraft] = useState<QuoteRequestDraft>({
    title: todayDraft?.title ?? todayRecommendation?.title ?? "",
    category_id: todayDraftCategory?.id ?? todayRecommendation?.categoryId ?? data.categories[0]?.id ?? "",
    delivery_region: todayDraft?.region ?? "",
    delivery_address: todayDraft?.delivery_address_snapshot ?? "",
    desired_delivery_date: "2026-07-10",
    need_tax_invoice: true,
    card_payment_required: false,
    description: todayDraft?.description ?? todayRecommendation?.description ?? "",
    attachment_note: "",
    previous_amount: 0,
    input_method: requestedInputMethod ?? "manual",
    original_text_input: todayRecommendation?.textInput ?? todayDraft?.description ?? "",
    template_name: "",
    previous_request_id: "",
    urgent: false,
    preferred_delivery_time: "오전 납품 선호",
    budget_min: 0,
    budget_max: 0,
    preferred_brand: "",
    allow_alternatives: true,
    include_delivery_fee: true,
    items: todayDraftItems?.length ? todayDraftItems : todayRecommendation?.items ?? [{ ...emptyItem }],
    attachments: [],
  });
  const [error, setError] = useState("");
  const selectedCategory = data.categories.find((category) => category.id === draft.category_id) ?? data.categories[0];
  const buyerIdsForPurchaseHistory = buyerIdsForSession;
  const previousPurchaseLookup = useMemo(
    () => buildPreviousPurchaseLookup(data, buyerIdsForPurchaseHistory),
    [data, buyerIdsForPurchaseHistory],
  );
  const qualityScore = useMemo(() => calculateRequestQuality({ ...draft, category_name: selectedCategory?.name }, draft.items, draft.attachments), [draft, selectedCategory]);
  const expectedSupplierCount = useMemo(
    () => estimateSupplierMatches(data, selectedCategory?.name ?? "", draft.delivery_region, draft.need_tax_invoice, draft.card_payment_required),
    [data, selectedCategory, draft.delivery_region, draft.need_tax_invoice, draft.card_payment_required],
  );
  const cleanItems = draft.items.filter((entry) => entry.item_name.trim());

  useEffect(() => {
    window.scrollTo({ top: 0, behavior: "smooth" });
  }, [step]);

  useEffect(() => {
    if (!todayDraftId || !todayDraft || todayDraft.status !== "draft") return;
    setData(markTodayQuoteDraftOpened(data, todayDraftId, todayDraft.business_id));
  }, [todayDraftId, todayDraft?.id, todayDraft?.business_id, todayDraft?.status]);

  function updateItem(index: number, key: keyof QuoteRequestDraft["items"][number], value: string | number | boolean) {
    setDraft((current) => ({
      ...current,
      items: current.items.map((entry, itemIndex) => (itemIndex === index ? { ...entry, [key]: value } : entry)),
    }));
  }

  function selectMethod(method: QuoteRequestInputMethod) {
    setDraft((current) => ({ ...current, input_method: method }));
    setStep(1);
  }

  function selectTemplate(templateName: string) {
    const template = requestTemplates.find((entry) => entry.name === templateName);
    if (!template) return;
    const category = data.categories.find((entry) => entry.name === template.category_name) ?? selectedCategory;
    setDraft((current) => ({
      ...current,
      input_method: "template",
      template_name: template.name,
      title: template.title,
      category_id: category?.id ?? current.category_id,
      description: template.description,
      items: template.items.map((entry) => ({ ...entry })),
    }));
    setStep(1);
  }

  function repeatRequest(previousRequest: QuoteRequest) {
    const previousItems = data.quote_request_items.filter((entry) => entry.quote_request_id === previousRequest.id);
    setDraft((current) => ({
      ...current,
      input_method: "repeat",
      previous_request_id: previousRequest.id,
      title: `${previousRequest.title} 재견적`,
      category_id: previousRequest.category_id,
      delivery_region: previousRequest.delivery_region,
      delivery_address: previousRequest.delivery_address ?? previousRequest.delivery_region,
      desired_delivery_date: current.desired_delivery_date,
      need_tax_invoice: previousRequest.need_tax_invoice,
      card_payment_required: previousRequest.card_payment_required,
      description: previousRequest.description,
      previous_amount: previousRequest.previous_amount ?? 0,
      preferred_delivery_time: previousRequest.preferred_delivery_time ?? current.preferred_delivery_time,
      budget_max: previousRequest.budget_max ?? 0,
      allow_alternatives: previousRequest.allow_alternatives ?? true,
      include_delivery_fee: previousRequest.include_delivery_fee ?? true,
      items: previousItems.map((entry) => ({
        item_name: entry.item_name,
        spec: entry.spec,
        quantity: entry.quantity,
        unit: entry.unit,
        memo: entry.memo,
        is_required: entry.is_required ?? true,
        allow_alternative: entry.allow_alternative ?? true,
        confidence_score: entry.confidence_score ?? 96,
        needs_review: false,
        review_reason: "",
      })),
    }));
    setStep(1);
  }

  function parseTextInput() {
    const parsedItems = parseItemsFromText(textInput);
    setDraft((current) => ({
      ...current,
      input_method: "text",
      original_text_input: textInput,
      title: current.title || `${selectedCategory?.name ?? "자재"} 견적 요청`,
      description: current.description || textInput,
      items: parsedItems,
    }));
  }

  function applyReceiptAnalysis(result: ReceiptAnalysisPreview, source: ReceiptAnalysisSource, notice = "") {
    const category = data.categories.find((entry) => entry.name === result.categoryName) ?? selectedCategory;
    setReceiptAnalysisPreview(result);
    setReceiptAnalysisSource(source);
    setReceiptAnalysisNotice(notice);
    setReceiptFileName(result.fileName);
    setDraft((current) => ({
      ...current,
      input_method: "photo",
      title: current.title || `${result.categoryName} 재견적 요청`,
      category_id: category?.id ?? current.category_id,
      description: current.description || `${result.supplierName || "업로드 이미지"}에서 자동 추출한 품목입니다. 품목과 수량을 확인한 뒤 견적을 요청합니다.`,
      attachment_note: result.fileName,
      previous_amount: result.totalAmount,
      budget_max: current.budget_max || Math.round(result.totalAmount * 0.95),
      original_text_input: result.rawText,
      items: result.items.length ? result.items : current.items,
      attachments: [
        result.attachment,
        ...current.attachments.filter((attachment) => attachment.file_name !== result.attachment.file_name),
      ],
    }));
    setError("");
  }

  async function analyzeReceiptPhoto() {
    const sourceType = "photo";
    if (!receiptImageFile) {
      setReceiptAnalysisNotice("분석할 이미지를 먼저 선택해 주세요. 구매영수증이나 자필 메모 사진을 사용할 수 있습니다.");
      return;
    }
    setReceiptAnalysisLoading(true);
    setError("");
    try {
      const result = await analyzeReceiptImageWithGemini(receiptImageFile, receiptFileName || receiptImageFile.name, sourceType);
      applyReceiptAnalysis(result, "gemini", "AI가 업로드 이미지를 읽어 품목 후보를 자동 입력했습니다.");
    } catch (analysisError) {
      console.warn("quote receipt analysis fallback used", analysisError);
      const fallback = analyzeReceiptPhotoForQuoteRequest(receiptFileName || receiptImageFile.name, sourceType);
      applyReceiptAnalysis(fallback, "mock", `${formatGeminiAnalysisError(analysisError)} 앱 내부 분석으로 임시 품목 초안을 만들었습니다. 저장 전 품목과 금액을 꼭 확인해 주세요.`);
    } finally {
      setReceiptAnalysisLoading(false);
    }
  }

  function updateReceiptImageFile(file: File | null) {
    setReceiptImageFile(file);
    setReceiptAnalysisNotice("");
    if (file) {
      setReceiptFileName(file.name);
    }
  }

  function goNext() {
    setError("");
    if (step === 1 && !draft.items.some((entry) => entry.item_name.trim())) {
      setError("품목을 1개 이상 입력하거나 템플릿/문장 분석으로 추가해 주세요.");
      return;
    }
    if (step === 2 && (!draft.delivery_region.trim() || !draft.desired_delivery_date)) {
      setError("배송 지역과 희망 납품일을 입력해 주세요.");
      return;
    }
    if (step === 2 && !isKoreaRegionOption(draft.delivery_region)) {
      setError("배송 지역은 검색 후 목록에서 표준 지역명을 선택해 주세요. 예: 서울 강남구");
      return;
    }
    setStep((current) => Math.min(wizardSteps.length - 1, current + 1));
  }

  async function submit(event: FormEvent) {
    event.preventDefault();
    if (!draft.delivery_region.trim() || !draft.desired_delivery_date || !draft.items.some((entry) => entry.item_name.trim())) {
      setError("배송 지역, 희망 납품일, 품목을 입력해 주세요.");
      return;
    }
    if (!isKoreaRegionOption(draft.delivery_region)) {
      setError("배송 지역은 검색 후 목록에서 표준 지역명을 선택해 주세요. 예: 서울 강남구");
      return;
    }
    if (todayDraft?.status === "submitted") {
      setError("이미 제출된 초안입니다. 다시 요청하려면 새 초안을 만들어주세요.");
      return;
    }

    const finalDraft = {
      ...draft,
      title: draft.title.trim() || `${selectedCategory?.name ?? "자재"} 견적 요청`,
    };

    if (isLiveModeReady() && authSession?.role === "buyer" && authSession.id) {
      const liveResult = await createLiveQuoteRequest(authSession.id, finalDraft);
      if (!liveResult.ok) {
        setError(`견적요청 저장에 실패했습니다. ${liveResult.error}`);
        return;
      }
      if (!liveResult.data) {
        setError("견적요청 저장 후 응답을 확인하지 못했습니다. 잠시 후 다시 시도해 주세요.");
        return;
      }
      const liveItemsResult = await listLiveQuoteRequestItemsForRequests([liveResult.data.id]);
      const nextData = mergeQuoteRequestState(data, [liveResult.data], liveItemsResult.ok ? liveItemsResult.data : []);
      setData(todayDraftId ? linkRequoteDraftToQuoteRequest(nextData, todayDraftId, liveResult.data.id, authSession.id) : nextData);
      navigate(`/app/requests/${liveResult.data.id}`);
      return;
    }

    const result = createQuoteRequest(data, finalDraft, authSession?.role === "buyer" ? authSession.id : "buyer-1");
    setData(todayDraftId ? linkRequoteDraftToQuoteRequest(result.data, todayDraftId, result.requestId, authSession?.id ?? "buyer-1") : result.data);
    navigate(`/app/requests/${result.requestId}`);
  }

  return (
    <Page>
      <BackButton onClick={() => navigate("/app/requests")} label="요청 목록" />
      <PageTitle eyebrow="구매자" title="필요한 자재를 편하게 알려주세요." desc="영수증 사진, 문장, 지난 구매 중 편한 방식으로 시작하고 마지막에 품목과 납품 조건만 확인합니다." />
      <form className="wizardShell" onSubmit={submit}>
        <div className="wizardSteps" aria-label="견적요청 작성 단계">
          {wizardSteps.map((label, index) => (
            <button className={index === step ? "wizardStep active" : index < step ? "wizardStep done" : "wizardStep"} type="button" onClick={() => setStep(index)} key={label}>
              <span>{index + 1}</span>
              <strong>{label}</strong>
            </button>
          ))}
        </div>
        {error && <div className="alert">{error}</div>}
        {todayDraft && (
          <div className="todayRecommendationNotice">
            <strong>오늘장사 추천으로 만든 견적요청 초안입니다.</strong>
            <span>지난 구매내역을 바탕으로 품목을 채웠어요. 수량, 규격, 납품일을 확인하고 필요한 부분을 수정한 뒤 제출해주세요.</span>
          </div>
        )}
        {todayRecommendation && (
          <div className="todayRecommendationNotice">
            <strong>오늘장사에서 추천된 견적요청입니다.</strong>
            <span>{todayRecommendation.label} 비용을 비교견적으로 확인해볼 수 있어요. 품목과 납품 조건을 확인한 뒤 제출해 주세요.</span>
          </div>
        )}
        {step === 0 && (
          <section className="wizardPanel">
            <SectionHeader title="어떻게 올릴까요?" />
            <p className="mutedText summaryLine">정확히 몰라도 괜찮아요. 규격을 모르시면 사진이나 메모를 남겨주세요.</p>
            <div className="methodGrid">
              <MethodCard icon={<Upload />} title="영수증 올리기" desc="영수증이나 자필 메모 사진을 올리면 AI가 품목을 자동 입력합니다." active={draft.input_method === "photo"} onClick={() => selectMethod("photo")} />
              <MethodCard icon={<FilePlus2 />} title="직접 입력하기" desc="품목명, 수량, 납품 조건을 직접 입력합니다." active={draft.input_method === "manual"} onClick={() => selectMethod("manual")} />
              <MethodCard icon={<RefreshCcw />} title="지난 구매 다시 요청하기" desc="지난 요청을 복사해 수량과 납품일만 바꿉니다." active={draft.input_method === "repeat"} onClick={() => selectMethod("repeat")} />
            </div>
          </section>
        )}
        {step === 1 && (
          <section className="wizardPanel">
            <div className="splitPanel">
              <div>
                <SectionHeader title="품목을 확인하세요" action="품목 추가" onAction={() => setDraft({ ...draft, items: [...draft.items, { ...emptyItem }] })} />
                <div className="categoryChoiceGrid compact">
                  {data.categories.map((category) => (
                    <button className={draft.category_id === category.id ? "categoryChoiceCard active" : "categoryChoiceCard"} type="button" onClick={() => setDraft({ ...draft, category_id: category.id })} key={category.id}>
                      <strong>{category.name}</strong>
                      <small>{draft.category_id === category.id ? "선택됨" : "탭해서 선택"}</small>
                      <span>{categoryDescriptions[category.name] ?? "요청 품목의 성격에 가장 가까운 카테고리"}</span>
                    </button>
                  ))}
                </div>
                {draft.input_method === "text" && (
                  <div className="aiReviewPanel">
                    <Field label="문장 입력">
                      <textarea value={textInput} onChange={(event) => setTextInput(event.target.value)} placeholder="예: 치킨박스 1000개, 소스컵 2000개, 봉투 대형 1000장 필요해요." />
                    </Field>
                    <button className="primaryButton compact" type="button" onClick={parseTextInput}>품목 후보 만들기</button>
                  </div>
                )}
                {(draft.input_method === "photo" || draft.input_method === "invoice") && (
                  <UploadMockPanel
                    attachments={draft.attachments}
                    fileName={receiptFileName}
                    onFileNameChange={setReceiptFileName}
                    onImageFileChange={updateReceiptImageFile}
                    onAnalyze={analyzeReceiptPhoto}
                    hasSelectedFile={Boolean(receiptImageFile)}
                    analysisPreview={receiptAnalysisPreview}
                    analysisSource={receiptAnalysisSource}
                    analysisNotice={receiptAnalysisNotice}
                    isAnalyzing={receiptAnalysisLoading}
                  />
                )}
                {draft.input_method === "template" && <TemplatePicker onSelect={selectTemplate} selectedName={draft.template_name} />}
                {draft.input_method === "repeat" && <RepeatRequestPanel data={data} onSelect={repeatRequest} selectedId={draft.previous_request_id} />}
                <ItemReviewEditor items={draft.items} previousPurchaseLookup={previousPurchaseLookup} onUpdate={updateItem} onRemove={(index) => setDraft({ ...draft, items: draft.items.filter((_, itemIndex) => itemIndex !== index) })} />
              </div>
              <QualityPreview score={qualityScore} expectedSupplierCount={expectedSupplierCount} />
            </div>
          </section>
        )}
        {step === 2 && (
          <section className="wizardPanel">
            <SectionHeader title="납품 조건을 입력하세요" />
            <div className="conditionGrid essentialConditions">
              <Field label="배송 지역">
                <RegionSearchField
                  value={draft.delivery_region}
                  onChange={(value) => setDraft((current) => ({ ...current, delivery_region: value }))}
                  required
                  selectionOnly
                  placeholder="배송 지역 검색: 서울 강남구"
                />
                <small className="fieldHelp">공급업체 매칭을 위해 목록에서 표준 지역명을 선택해 주세요.</small>
              </Field>
              <Field label="희망 납품일">
                <input type="date" value={draft.desired_delivery_date} onChange={(event) => setDraft({ ...draft, desired_delivery_date: event.target.value })} />
              </Field>
            </div>
            <div className="toggleGrid">
              <Toggle checked={draft.need_tax_invoice} label="세금계산서 필요" onChange={(checked) => setDraft({ ...draft, need_tax_invoice: checked })} />
              <Toggle checked={draft.card_payment_required} label="카드결제 필요" onChange={(checked) => setDraft({ ...draft, card_payment_required: checked })} />
            </div>
            <button className="ghostButton compact showMoreButton" type="button" onClick={() => setShowMoreConditions((current) => !current)}>
              {showMoreConditions ? "선택 입력 닫기" : "선택 입력 더보기"}
            </button>
            {showMoreConditions && (
              <div className="optionalPanel">
                <div className="conditionGrid">
                  <Field label="요청 제목">
                    <input value={draft.title} onChange={(event) => setDraft({ ...draft, title: event.target.value })} placeholder={`${selectedCategory?.name ?? "자재"} 견적 요청`} />
                  </Field>
                  <Field label="상세 위치">
                    <input value={draft.delivery_address} onChange={(event) => setDraft({ ...draft, delivery_address: event.target.value })} placeholder="예: 월계역 인근 매장" />
                  </Field>
                  <Field label="희망 시간">
                    <input value={draft.preferred_delivery_time} onChange={(event) => setDraft({ ...draft, preferred_delivery_time: event.target.value })} placeholder="예: 오전 10시 전" />
                  </Field>
                  <Field label="선호 브랜드">
                    <input value={draft.preferred_brand} onChange={(event) => setDraft({ ...draft, preferred_brand: event.target.value })} placeholder="없으면 비워두세요" />
                  </Field>
                  <Field label="기존 거래가">
                    <input type="number" min="0" value={draft.previous_amount} onChange={(event) => setDraft({ ...draft, previous_amount: Number(event.target.value) })} />
                  </Field>
                  <Field label="예산 최대">
                    <input type="number" min="0" value={draft.budget_max} onChange={(event) => setDraft({ ...draft, budget_max: Number(event.target.value) })} />
                  </Field>
                </div>
                <Field label="요청 메모">
                  <textarea value={draft.description} onChange={(event) => setDraft({ ...draft, description: event.target.value })} placeholder="중요한 납품 조건만 짧게 적어주세요." />
                </Field>
                <div className="toggleGrid">
                  <Toggle checked={draft.include_delivery_fee} label="배송비 포함 견적" onChange={(checked) => setDraft({ ...draft, include_delivery_fee: checked })} />
                  <Toggle checked={draft.urgent} label="긴급 요청" onChange={(checked) => setDraft({ ...draft, urgent: checked })} />
                  <Toggle checked={draft.allow_alternatives} label="대체품 제안 허용" onChange={(checked) => setDraft({ ...draft, allow_alternatives: checked })} />
                </div>
              </div>
            )}
          </section>
        )}
        {step === 3 && (
          <section className="wizardPanel">
            <SectionHeader title="요청 내용을 확인하세요" />
            <div className="summaryPanel">
              <QualityMeter score={qualityScore} />
              <div className="summaryFacts">
                <span>입력 방식: {requestInputMethodLabels[draft.input_method]}</span>
                <span>카테고리: {selectedCategory?.name}</span>
                <span>품목: {cleanItems.length}개</span>
                <span>예상 응답 업체: {expectedSupplierCount}곳</span>
                <span>희망 납품: {draft.desired_delivery_date} {draft.preferred_delivery_time}</span>
                <span>배송 지역: {draft.delivery_region || "미입력"}</span>
              </div>
              <div className="summaryItemList">
                {cleanItems.map((entry, index) => (
                  <span key={`${entry.item_name}-${index}`}>{entry.item_name} · {entry.quantity}{entry.unit} · {entry.spec || "규격 미입력"}</span>
                ))}
              </div>
              {draft.attachments.length > 0 && <AttachmentStatusList attachments={draft.attachments} />}
              <SavingsNotice savings={calculateEstimatedSavings(Number(draft.previous_amount) || undefined, Number(draft.budget_max) || undefined)} previousAmount={Number(draft.previous_amount) || undefined} />
            </div>
          </section>
        )}
        <div className="wizardActions">
          <button className="secondaryButton" type="button" onClick={() => (step === 0 ? navigate("/app/requests") : setStep((current) => current - 1))}>
            {step === 0 ? "취소" : "이전"}
          </button>
          {step < wizardSteps.length - 1 ? (
            <button className="primaryButton" type="button" onClick={goNext}>
              다음
              <ArrowRight size={17} />
            </button>
          ) : (
            <button className="primaryButton" type="submit">
              <Check size={18} />
              견적요청 완료
            </button>
          )}
        </div>
      </form>
    </Page>
  );
}

function RequestsPage({ data, navigate, authSession }: PageProps & { authSession?: AppAuthSession | null }) {
  const buyerIds = getBuyerIdsForSession(data, authSession);
  const requests = authSession?.role === "buyer"
    ? data.quote_requests.filter((request) => buyerIds.has(request.buyer_id) && (!isLiveModeReady() || isLiveRecordId(request.id) || request.buyer_id !== authSession.id))
    : data.quote_requests;
  return (
    <Page>
      <PageTitle eyebrow="구매자" title="내 견적요청" desc="등록한 요청과 도착한 견적을 한곳에서 확인합니다." />
      <div className="toolbar requestListToolbar">
        <button className="primaryButton compact" type="button" onClick={() => navigate("/app/requests/new")}>
          <Plus size={16} />
          새 요청
        </button>
      </div>
      <RequestList data={data} requests={requests} navigate={navigate} />
    </Page>
  );
}

function RequestDetailPage({ data, navigate, setData, requestId }: MutatingPageProps & { requestId: string }) {
  const [quoteToConfirm, setQuoteToConfirm] = useState<Quote | null>(null);
  const request = data.quote_requests.find((entry) => entry.id === requestId);
  if (!request) return <NotFound navigate={navigate} />;
  const currentRequest = request;

  const items = data.quote_request_items.filter((entry) => entry.quote_request_id === currentRequest.id);
  const quotes = data.quotes.filter((entry) => entry.quote_request_id === currentRequest.id);
  const deal = data.deals.find((entry) => entry.quote_request_id === currentRequest.id);
  const selectedQuote = quotes.find((entry) => entry.id === currentRequest.selected_quote_id || entry.id === deal?.selected_quote_id);
  const cheapest = quotes.reduce<Quote | null>((winner, current) => (!winner || current.final_amount < winner.final_amount ? current : winner), null);
  const fastest = quotes.reduce<Quote | null>((winner, current) => (!winner || current.available_delivery_date < winner.available_delivery_date ? current : winner), null);
  const recommended = quotes.reduce<Quote | null>((winner, current) => {
    const currentScore = quoteRecommendationScore(data, current, cheapest?.id === current.id, fastest?.id === current.id, items);
    const winnerScore = winner ? quoteRecommendationScore(data, winner, cheapest?.id === winner.id, fastest?.id === winner.id, items) : -1;
    return currentScore > winnerScore ? current : winner;
  }, null);

  function confirmQuoteSelection() {
    if (!quoteToConfirm) return;
    const result = createDealFromQuote(data, currentRequest.id, quoteToConfirm.id);
    setData(result.data);
    setQuoteToConfirm(null);
    if (result.dealId) navigate(`/app/deals/${result.dealId}`);
  }

  function askSupplier(quote: Quote) {
    const result = ensureRequestMessageThread(data, currentRequest.id, quote.supplier_id);
    setData(result.data);
    navigate(`/app/requests/${currentRequest.id}/messages`);
  }

  return (
    <Page>
      <BackButton onClick={() => navigate("/app/requests")} label="요청 목록" />
      <RequestSummary data={data} request={currentRequest} items={items} />
      <div className="toolbar messageShortcut">
        <button className="secondaryButton compact" type="button" onClick={() => navigate(`/app/requests/${currentRequest.id}/messages`)}>
          <Bell size={16} />
          업체에 문의하기
        </button>
      </div>
      {deal && selectedQuote && (
        <DealNotice data={data} deal={deal} quote={selectedQuote} onOpen={() => navigate(`/app/deals/${deal.id}`)} />
      )}
      <SectionHeader title="도착한 견적 비교" />
      {quotes.length === 0 ? (
        <EmptyState icon={<SearchCheck />} title="아직 도착한 견적이 없습니다." desc="공급업체 화면에서 샘플 견적을 제출해 흐름을 확인할 수 있습니다." />
      ) : (
        <>
          <QuoteComparisonSummary data={data} quotes={quotes} items={items} recommended={recommended} cheapest={cheapest} fastest={fastest} />
          <div className="quoteCompareGrid">
            {quotes.map((quoteEntry) => (
              <QuoteCard
                key={quoteEntry.id}
                data={data}
                quote={quoteEntry}
                requestItems={items}
                isRecommended={recommended?.id === quoteEntry.id}
                isCheapest={cheapest?.id === quoteEntry.id}
                isFastest={fastest?.id === quoteEntry.id}
                isSelected={selectedQuote?.id === quoteEntry.id}
                isRejected={quoteEntry.status === "rejected"}
                onSelect={() => setQuoteToConfirm(quoteEntry)}
                onAskSupplier={() => askSupplier(quoteEntry)}
              />
            ))}
          </div>
          <QuoteItemComparisonTable data={data} quotes={quotes} items={items} />
        </>
      )}
      {quoteToConfirm && (
        <QuoteConfirmModal
          data={data}
          quote={quoteToConfirm}
          onCancel={() => setQuoteToConfirm(null)}
          onConfirm={confirmQuoteSelection}
        />
      )}
    </Page>
  );
}

function BuyerDealsPage({ data, navigate, authSession }: PageProps & { authSession?: AppAuthSession | null }) {
  const [filter, setFilter] = useState("전체");
  const buyerIds = getBuyerIdsForSession(data, authSession);
  const buyerDeals = data.deals.filter((deal) => buyerIds.has(deal.buyer_id));
  const visibleDeals = buyerDeals.filter((deal) => filter === "전체" || dealGroup(deal.status) === filter);
  const inProgress = buyerDeals.filter((deal) => ["pending_confirmation", "confirmed", "preparing", "delivering", "delivered"].includes(deal.status)).length;
  const completed = buyerDeals.filter((deal) => deal.status === "completed").length;
  const monthAmount = buyerDeals.reduce((sum, deal) => sum + deal.final_amount, 0);
  const savings = buyerDeals.reduce((sum, deal) => sum + calculateEstimatedSavings(deal.previous_amount, deal.final_amount).amount, 0);
  const accountingPending = data.purchase_records.filter((record) => buyerIds.has(record.buyer_id) && record.accounting_status === "pending").length;

  return (
    <Page>
      <PageTitle eyebrow="구매자" title="거래내역" desc="선택한 견적이 거래로 전환된 뒤 납품 상태와 구매내역을 관리합니다." />
      <div className="dashboardGrid">
        <Metric label="진행 중 거래" value={`${inProgress}건`} icon={<PackageCheck />} />
        <Metric label="완료 거래" value={`${completed}건`} icon={<Check />} />
        <Metric label="이번 달 구매액" value={money(monthAmount)} icon={<ReceiptText />} />
        <Metric label="예상 절감액" value={money(savings)} icon={<BadgeCheck />} />
      </div>
      <div className="ledgerShortcut">
        <p className="mutedText summaryLine">장부 반영 대기 {accountingPending}건</p>
        <div className="toolbar">
          <button className="secondaryButton compact" type="button" onClick={() => navigate("/app/purchases")}>
            <ReceiptText size={16} />
            구매내역
          </button>
          <button className="secondaryButton compact" type="button" onClick={() => navigate("/app/reviews")}>
            <BadgeCheck size={16} />
            작성한 후기
          </button>
          <button className="primaryButton compact" type="button" onClick={() => navigate("/app/accounting/pending")}>
            <Landmark size={16} />
            장부 대기
          </button>
        </div>
      </div>
      <FilterTabs options={["전체", "진행 중", "완료", "취소", "문제 발생"]} active={filter} onChange={setFilter} />
      <DealTable data={data} deals={visibleDeals} navigate={navigate} basePath="/app/deals" role="buyer" />
    </Page>
  );
}

function BuyerReviewsPage({ data, navigate, authSession }: PageProps & { authSession?: AppAuthSession | null }) {
  if (authSession?.role === "supplier") return <RoleAccessDenied role="supplier" attemptedRole="buyer" navigate={navigate} />;

  const sessionBuyerIds = getBuyerIdsForSession(data, authSession);
  const buyerIds = sessionBuyerIds.size ? sessionBuyerIds : new Set([authSession?.id ?? "buyer-1"]);
  const reviews = data.reviews
    .filter((review) => buyerIds.has(review.buyer_id))
    .sort((a, b) => b.created_at.localeCompare(a.created_at));
  const averageRating = reviews.length ? reviews.reduce((sum, review) => sum + review.rating_overall, 0) / reviews.length : 0;
  const reorderReviews = reviews.filter((review) => review.would_reorder).length;
  const repliedReviews = reviews.filter((review) => data.review_replies.some((reply) => reply.review_id === review.id && reply.status === "active")).length;
  const hiddenReviews = reviews.filter((review) => review.status !== "active").length;

  return (
    <Page>
      <PageTitle eyebrow="구매자" title="내가 작성한 후기" desc="거래 완료 후 남긴 업체 후기를 한곳에서 확인합니다." />
      <div className="dashboardGrid">
        <Metric label="작성한 후기" value={`${reviews.length}건`} icon={<BadgeCheck />} />
        <Metric label="평균 평점" value={reviews.length ? `${averageRating.toFixed(1)}점` : "-"} icon={<Check />} />
        <Metric label="공급사 답변" value={`${repliedReviews}건`} icon={<MessageCircle />} />
        <Metric label="재거래 의향" value={`${reorderReviews}건`} icon={<RefreshCcw />} />
      </div>
      {repliedReviews > 0 && (
        <section className="statusNotice approved">
          <MessageCircle size={22} />
          <div>
            <strong>공급사 답변이 {repliedReviews}건 도착했습니다.</strong>
            <p>작성한 후기 카드에서 공급업체의 답변을 바로 확인할 수 있습니다.</p>
          </div>
        </section>
      )}
      {hiddenReviews > 0 && (
        <section className="statusNotice">
          <ShieldCheck size={22} />
          <div>
            <strong>숨김 또는 검토 중인 후기가 {hiddenReviews}건 있습니다.</strong>
            <p>운영 검토 상태가 바뀌면 공개 여부도 함께 반영됩니다.</p>
          </div>
        </section>
      )}
      {reviews.length ? (
        <div className="reviewList">
          {reviews.map((review) => {
            const deal = data.deals.find((entry) => entry.id === review.deal_id);
            const reply = data.review_replies.find((entry) => entry.review_id === review.id && entry.status === "active");
            const ratingItems = [
              `가격 ${review.rating_price}점`,
              `납품 ${review.rating_delivery}점`,
              `품질 ${review.rating_quality}점`,
              `소통 ${review.rating_communication}점`,
            ];

            return (
              <article className="reviewCard" key={review.id}>
                <div className="cardTopline">
                  <StatusBadge tone={reviewStatusTone(review.status)}>{reviewStatusLabels[review.status]}</StatusBadge>
                  <span>{review.is_public ? "공개" : "비공개"}</span>
                </div>
                <strong>{supplierName(data, review.supplier_id)}</strong>
                <p>{deal?.title ?? "거래 정보 확인 중"} · 평점 {review.rating_overall}점</p>
                <div className="detailMeta">
                  {ratingItems.map((item) => <span key={item}>{item}</span>)}
                  <span>{review.would_reorder ? "재거래 의향 있음" : "재거래 의향 없음"}</span>
                </div>
                <p>{review.content}</p>
                {reply ? (
                  <div className="buyerReviewReplyBox">
                    <div>
                      <MessageCircle size={16} />
                      <strong>공급사 답변</strong>
                      <span>{reply.created_at.slice(0, 10)}</span>
                    </div>
                    <p>{reply.content}</p>
                  </div>
                ) : (
                  <div className="buyerReviewReplyPending">
                    <MessageCircle size={16} />
                    <span>공급사 답변 대기 중</span>
                  </div>
                )}
                <small>{review.created_at.slice(0, 10)}</small>
                <div className="formActions">
                  <button className="secondaryButton compact" type="button" onClick={() => navigate(`/app/deals/${review.deal_id}`)}>
                    <ReceiptText size={16} />
                    거래 보기
                  </button>
                  <button className="ghostButton compact" type="button" onClick={() => navigate(`/app/suppliers/${review.supplier_id}`)}>
                    <Store size={16} />
                    업체 보기
                  </button>
                </div>
              </article>
            );
          })}
        </div>
      ) : (
        <EmptyState icon={<BadgeCheck />} title="작성한 후기가 없습니다." desc="거래 완료 후 후기를 남기면 이곳에 모입니다." actionLabel="완료 거래 보기" onAction={() => navigate("/app/deals")} />
      )}
    </Page>
  );
}

