function ReviewCard({ review }: { review: { id: string; rating: number; content: string; created_at: string } }) {
  return (
    <article className="reviewCard">
      <strong>평점 {review.rating}</strong>
      <p>{review.content}</p>
      <small>{review.created_at.slice(0, 10)}</small>
    </article>
  );
}

function RequestList({ data, requests, navigate }: { data: AppData; requests: QuoteRequest[]; navigate: Navigate }) {
  if (requests.length === 0) return <EmptyState icon={<ClipboardList />} title="표시할 요청이 없습니다." desc="새 견적요청을 등록해 보세요." />;

  return (
    <div className="requestGrid">
      {requests.map((request) => {
        const items = data.quote_request_items.filter((entry) => entry.quote_request_id === request.id);
        const quotes = data.quotes.filter((entry) => entry.quote_request_id === request.id);
        const qualityScore = request.request_quality_score ?? calculateRequestQuality(request, items);
        return (
          <article className="requestCard" key={request.id} onClick={() => navigate(`/app/requests/${request.id}`)}>
            <div className="cardTopline">
              <StatusBadge tone={request.status === "selected" ? "green" : request.status === "open" ? "orange" : "blue"}>
                {requestStatusLabels[request.status]}
              </StatusBadge>
              <span>{request.category_name}</span>
            </div>
            <h3>{request.title}</h3>
            <p>{request.description}</p>
            <div className="cardQualityLine">
              <span>품질 {qualityScore}점</span>
              <span>{request.input_method ? requestInputMethodLabels[request.input_method] : "직접 입력"}</span>
              {request.urgent && <span>긴급</span>}
            </div>
            <div className="cardMeta">
              <span><CalendarDays size={15} /> {request.desired_delivery_date}</span>
              <span><PackageCheck size={15} /> 품목 {items.length}개</span>
              <span><ReceiptText size={15} /> 견적 {quotes.length}건</span>
            </div>
            <button className="textLink" type="button">
              상세 보기 <ArrowRight size={15} />
            </button>
          </article>
        );
      })}
    </div>
  );
}

function RequestSummary({ data, request, items }: { data: AppData; request: QuoteRequest; items: QuoteRequestItem[] }) {
  const quoteCount = data.quotes.filter((quoteEntry) => quoteEntry.quote_request_id === request.id).length;
  const attachments = data.quote_attachments.filter((attachment) => attachment.quote_request_id === request.id);
  const qualityScore = request.request_quality_score ?? calculateRequestQuality(request, items, attachments);
  const expectedSupplierCount = request.expected_supplier_count ?? estimateSupplierMatches(data, request.category_name, request.delivery_region, request.need_tax_invoice, request.card_payment_required);
  const estimatedSelectedAmount = request.previous_amount && request.estimated_savings_amount ? request.previous_amount - request.estimated_savings_amount : undefined;
  const savings = calculateEstimatedSavings(request.previous_amount, estimatedSelectedAmount);
  const budgetLabel = request.budget_min || request.budget_max
    ? `${request.budget_min ? money(request.budget_min) : "하한 없음"} ~ ${request.budget_max ? money(request.budget_max) : "상한 없음"}`
    : "미입력";
  const conditionGroups: Array<{ title: string; facts: Array<{ label: string; value: string; strong?: boolean }> }> = [
    {
      title: "배송 조건",
      facts: [
        { label: "지역", value: request.delivery_region },
        { label: "희망 납품일", value: request.desired_delivery_date },
        ...(request.preferred_delivery_time ? [{ label: "희망 시간", value: request.preferred_delivery_time }] : []),
        ...(request.delivery_address ? [{ label: "상세 위치", value: request.delivery_address }] : []),
      ],
    },
    {
      title: "결제/증빙",
      facts: [
        { label: "세금계산서", value: yesNo(request.need_tax_invoice), strong: request.need_tax_invoice },
        { label: "카드결제 필수", value: yesNo(request.card_payment_required), strong: request.card_payment_required },
        { label: "배송비 포함", value: yesNo(request.include_delivery_fee ?? true), strong: request.include_delivery_fee ?? true },
      ],
    },
    {
      title: "요청 옵션",
      facts: [
        { label: "입력 방식", value: request.input_method ? requestInputMethodLabels[request.input_method] : "직접 입력" },
        { label: "대체품 허용", value: yesNo(request.allow_alternatives ?? true), strong: request.allow_alternatives ?? true },
        { label: "예산", value: budgetLabel },
        ...(request.preferred_brand ? [{ label: "선호 브랜드", value: request.preferred_brand }] : []),
      ],
    },
  ];

  return (
    <section className="detailBand requestSummaryPanel">
      <div className="detailHeader">
        <div>
          <span className="eyebrow">{request.category_name}</span>
          <h1>{request.title}</h1>
          <p>{request.description}</p>
        </div>
        <StatusBadge tone={request.status === "selected" ? "green" : request.status === "open" ? "orange" : "blue"}>{requestStatusLabels[request.status]}</StatusBadge>
      </div>
      <div className="requestInsightGrid requestSummaryMetrics">
        <QualityMeter score={qualityScore} />
        <div className="matchEstimate">
          <span>예상 응답 업체</span>
          <strong>{expectedSupplierCount}곳</strong>
        </div>
        <div className="matchEstimate">
          <span>예상 절감</span>
          <strong>{request.estimated_savings_amount ? money(request.estimated_savings_amount) : savings.amount ? money(savings.amount) : "계산 전"}</strong>
        </div>
        <div className="matchEstimate">
          <span>도착 견적</span>
          <strong>{quoteCount}건</strong>
        </div>
      </div>
      <div className="requestConditionGrid" aria-label="견적 요청 조건">
        {conditionGroups.map((group) => (
          <div className="requestConditionGroup" key={group.title}>
            <strong>{group.title}</strong>
            <dl>
              {group.facts.map((fact) => (
                <div className={fact.strong ? "strong" : ""} key={`${group.title}-${fact.label}`}>
                  <dt>{fact.label}</dt>
                  <dd>{fact.value}</dd>
                </div>
              ))}
            </dl>
          </div>
        ))}
      </div>
      {request.urgent && <div className="requestUrgentNotice">긴급 요청입니다. 납품 가능 여부와 대체품 가능 여부를 먼저 확인해 주세요.</div>}
      <div className="requestItemList" aria-label="요청 품목">
        {items.map((itemEntry) => (
          <article className="requestItemCard" key={itemEntry.id}>
            <div>
              <span className="requestItemQuantity">{itemEntry.quantity}{itemEntry.unit}</span>
              <strong>{itemEntry.item_name}</strong>
              <p>{itemEntry.spec || "규격 미입력"}</p>
            </div>
            <div className="requestItemMeta">
              <span className={itemEntry.is_required === false ? "" : "strong"}>{itemEntry.is_required === false ? "선택 품목" : "필수 품목"}</span>
              <span>{itemEntry.allow_alternative === false ? "대체 불가" : "대체 가능"}</span>
              {itemEntry.needs_review && <span className="warning">확인 필요</span>}
            </div>
            {itemEntry.memo && <small className="requestItemMemo">{itemEntry.memo}</small>}
          </article>
        ))}
      </div>
      {attachments.length > 0 && <AttachmentStatusList attachments={attachments.map((attachment) => ({
        file_name: attachment.file_name,
        file_type: attachment.file_type,
        analysis_status: attachment.analysis_status ?? "uploaded",
        extracted_text: attachment.extracted_text ?? "",
      }))} />}
      {request.attachment_note && <p className="mutedText">첨부 메모: {request.attachment_note}</p>}
    </section>
  );
}

function MethodCard({ icon, title, desc, active, onClick }: { icon: ReactNode; title: string; desc: string; active: boolean; onClick: () => void }) {
  return (
    <button className={active ? "methodCard active" : "methodCard"} type="button" onClick={onClick}>
      <span className="tileIcon">{icon}</span>
      <strong>{title}</strong>
      <span>{desc}</span>
    </button>
  );
}

function QualityPreview({ score, expectedSupplierCount }: { score: number; expectedSupplierCount: number }) {
  return (
    <aside className="qualityPreview">
      <QualityMeter score={score} />
      <div className="matchEstimate">
        <span>예상 응답 업체</span>
        <strong>{expectedSupplierCount}곳</strong>
      </div>
      <p className="mutedText">품목명, 규격, 납품 조건, 예산 정보가 채워질수록 공급업체가 빠르게 견적할 수 있습니다.</p>
    </aside>
  );
}

function SupplierRequestInsight({ request, qualityScore, attachmentsCount }: { request: QuoteRequest; qualityScore: number; attachmentsCount: number }) {
  return (
    <section className="supplierInsight">
      <QualityMeter score={qualityScore} />
      <div className="summaryFacts">
        <span>입력 방식: {request.input_method ? requestInputMethodLabels[request.input_method] : "직접 입력"}</span>
        <span>첨부: {attachmentsCount}개</span>
        <span>배송비 포함 요청: {yesNo(request.include_delivery_fee ?? true)}</span>
        <span>대체품 제안: {yesNo(request.allow_alternatives ?? true)}</span>
        {request.budget_max && <span>예산 상한: {money(request.budget_max)}</span>}
      </div>
    </section>
  );
}

function SupplierQuoteFitPanel({ supplier, request }: { supplier: SupplierProfile; request: QuoteRequest }) {
  const matchScore = calculateSupplierMatchScore(supplier, request);
  const checks = [
    { label: "카테고리 일치", ok: supplier.categories.some((category) => normalizeSupplierCategoryFilter(category) === normalizeSupplierCategoryFilter(request.category_name)) },
    { label: "납품 지역 적합", ok: calculateSupplierMatchScore(supplier, { ...request, need_tax_invoice: false, card_payment_required: false }) >= 70 },
    { label: "세금계산서 조건", ok: !request.need_tax_invoice || supplier.tax_invoice_available },
    { label: "카드결제 조건", ok: !request.card_payment_required || supplier.card_payment_available },
    { label: "긴급 대응", ok: !request.urgent || !!supplier.urgent_delivery_available },
  ];
  return (
    <section className="supplierFitPanel">
      <div>
        <span className="eyebrow">내 업체 조건과의 일치 여부</span>
        <h2>이 요청은 귀사의 취급 카테고리와 납품 지역에 적합합니다.</h2>
        <p>매칭 점수 {matchScore}점 · 기본 견적 유효기간 {supplier.default_quote_valid_days ?? 3}일 · 배송비 정책: {supplier.delivery_fee_policy ?? "협의"}</p>
      </div>
      <div className="fitCheckGrid">
        {checks.map((check) => (
          <span className={check.ok ? "fitCheck ok" : "fitCheck warn"} key={check.label}>{check.label}</span>
        ))}
      </div>
    </section>
  );
}

function QualityMeter({ score }: { score: number }) {
  const label = score >= 85 ? "매우 좋음" : score >= 70 ? "좋음" : score >= 55 ? "보완 권장" : "정보 부족";
  return (
    <div className="qualityMeter">
      <div>
        <span>요청 품질</span>
        <strong>{score}점</strong>
      </div>
      <div className="qualityBar" aria-label={`요청 품질 ${score}점`}>
        <span style={{ width: `${score}%` }} />
      </div>
      <small>{label}</small>
    </div>
  );
}

function UploadMockPanel({
  attachments,
  fileName,
  onFileNameChange,
  onImageFileChange,
  onAnalyze,
  hasSelectedFile,
  analysisPreview,
  analysisSource,
  analysisNotice,
  isAnalyzing,
}: {
  attachments: QuoteAttachmentDraft[];
  fileName: string;
  onFileNameChange: (value: string) => void;
  onImageFileChange: (file: File | null) => void;
  onAnalyze: () => void;
  hasSelectedFile: boolean;
  analysisPreview: ReceiptAnalysisPreview | null;
  analysisSource: ReceiptAnalysisSource;
  analysisNotice: string;
  isAnalyzing: boolean;
}) {
  return (
    <div className={isAnalyzing ? "uploadMockPanel analyzing" : "uploadMockPanel"} aria-busy={isAnalyzing}>
      <div className="receiptUploadHeader">
        <span className="tileIcon"><ReceiptText size={20} /></span>
        <div>
          <strong>영수증·메모 이미지로 품목 자동 입력</strong>
          <p>구매영수증이나 자필 주문 메모를 올리면 AI가 품목명, 규격, 수량을 채웁니다.</p>
        </div>
      </div>
      <div className="receiptUploadGrid">
        <Field label="이미지 파일">
          <input
            type="file"
            accept="image/png,image/jpeg,image/webp,image/heic,image/heif,image/*"
            onChange={(event) => {
              onImageFileChange(event.target.files?.[0] ?? null);
              event.currentTarget.value = "";
            }}
          />
        </Field>
        <Field label="메모 또는 파일명">
          <input value={fileName} onChange={(event) => onFileNameChange(event.target.value)} placeholder="예: 7월 포장재 구매영수증" />
        </Field>
        <div className="receiptUploadActions">
          <button className="primaryButton compact" type="button" onClick={onAnalyze} disabled={isAnalyzing || !hasSelectedFile}>
            <SearchCheck size={16} />
            {isAnalyzing ? "AI가 분석 중입니다." : "AI로 자동 입력"}
          </button>
        </div>
      </div>
      <div className={hasSelectedFile ? "receiptUploadStatus ready" : "receiptUploadStatus"}>
        <strong>{hasSelectedFile ? "이미지 선택 완료" : "이미지를 선택해 주세요"}</strong>
        <span>{hasSelectedFile ? `${fileName || "선택한 이미지"}를 분석할 준비가 되었습니다.` : "실제 영수증이나 자필 메모 이미지를 선택하면 AI 자동 입력 버튼이 활성화됩니다."}</span>
      </div>
      {isAnalyzing && (
        <div className="receiptAnalysisLoading" role="status" aria-live="assertive">
          <div className="spinner large" aria-hidden="true" />
          <strong>AI가 분석 중입니다.</strong>
          <p>업로드한 이미지에서 품목명, 규격, 수량을 읽고 있습니다. 잠시만 기다려 주세요.</p>
          <div className="analysisLoadingSteps" aria-hidden="true">
            <span>이미지 확인</span>
            <span>품목 추출</span>
            <span>자동 입력 준비</span>
          </div>
        </div>
      )}
      {analysisNotice && <p className="receiptAnalysisNotice">{analysisNotice}</p>}
      {analysisPreview && (
        <div className="receiptAnalysisResult">
          <div>
            <span className="eyebrow">{analysisSource === "gemini" ? "AI 분석 완료" : "자동 분석 완료"}</span>
            <strong>{analysisPreview.supplierName} · {analysisPreview.categoryName}</strong>
            <p>업로드 이미지에서 {analysisPreview.items.length}개 품목을 자동 입력했습니다. 품목 검토 단계에서 수량과 규격을 수정할 수 있습니다.</p>
          </div>
          <div className="receiptAnalysisMeta">
            <span>기존 구매금액 {money(analysisPreview.totalAmount)}</span>
            <span>신뢰도 {analysisPreview.confidenceScore}%</span>
            <span>{analysisPreview.fileName}</span>
          </div>
          <div className="receiptItemChips">
            {analysisPreview.items.map((item, index) => (
              <span key={`${item.item_name}-${index}`}>{item.item_name} {item.quantity}{item.unit}</span>
            ))}
          </div>
        </div>
      )}
      {attachments.length > 0 && <AttachmentStatusList attachments={attachments} />}
    </div>
  );
}

function TemplatePicker({ selectedName, onSelect }: { selectedName: string; onSelect: (name: string) => void }) {
  return (
    <div className="templateGrid">
      {requestTemplates.map((template) => (
        <button className={selectedName === template.name ? "templateCard active" : "templateCard"} type="button" onClick={() => onSelect(template.name)} key={template.name}>
          <strong>{template.name}</strong>
          <span>{template.category_name} · {template.items.length}개 품목</span>
          <small>{template.description}</small>
        </button>
      ))}
    </div>
  );
}

function RepeatRequestPanel({ data, selectedId, onSelect }: { data: AppData; selectedId: string; onSelect: (request: QuoteRequest) => void }) {
  return (
    <div className="repeatList">
      {data.quote_requests.slice(0, 4).map((request) => {
        const itemCount = data.quote_request_items.filter((entry) => entry.quote_request_id === request.id).length;
        return (
          <button className={selectedId === request.id ? "repeatCard active" : "repeatCard"} type="button" onClick={() => onSelect(request)} key={request.id}>
            <strong>{request.title}</strong>
            <span>{request.category_name} · {itemCount}개 품목 · {request.delivery_region}</span>
          </button>
        );
      })}
    </div>
  );
}

function ItemReviewEditor({
  items,
  previousPurchaseLookup,
  onUpdate,
  onRemove,
}: {
  items: QuoteRequestDraft["items"];
  previousPurchaseLookup: Map<string, PreviousPurchaseInfo>;
  onUpdate: (index: number, key: keyof QuoteRequestDraft["items"][number], value: string | number | boolean) => void;
  onRemove: (index: number) => void;
}) {
  return (
    <div className="itemReviewEditor">
      {items.map((entry, index) => {
        const previousPurchase = findPreviousPurchaseForItem(previousPurchaseLookup, entry.item_name);
        return (
          <article className={entry.needs_review ? "itemReviewRow needsReview" : "itemReviewRow"} key={`item-${index}`}>
            <div className="itemReviewNumber" aria-hidden="true">{index + 1}</div>
            <div className="itemReviewMain">
              <div className="itemReviewTopLine">
                <label className="itemNameField">
                  <span>품목명</span>
                  <input value={entry.item_name} onChange={(event) => onUpdate(index, "item_name", event.target.value)} placeholder="품목명" />
                </label>
                <button className="ghostButton compact itemRemoveButton" type="button" onClick={() => onRemove(index)}>삭제</button>
              </div>
              <div className="itemReviewSummaryGrid">
                <label className="compactField">
                  <span>수량</span>
                  <input type="number" min="1" value={entry.quantity} onChange={(event) => onUpdate(index, "quantity", Number(event.target.value))} aria-label="수량" />
                </label>
                <label className="compactField">
                  <span>단위</span>
                  <input value={entry.unit} onChange={(event) => onUpdate(index, "unit", event.target.value)} aria-label="단위" />
                </label>
                <div className={previousPurchase ? "previousPurchaseBox hasHistory" : "previousPurchaseBox"}>
                  <span>이전 구매</span>
                  {previousPurchase ? (
                    <>
                      <strong>{money(previousPurchase.unitPrice)} / {previousPurchase.unit || entry.unit || "개"}</strong>
                      <small>{previousPurchase.date} · {previousPurchase.supplierName} · {previousPurchase.quantity}{previousPurchase.unit} {money(previousPurchase.totalAmount)}</small>
                    </>
                  ) : (
                    <>
                      <strong>기록 없음</strong>
                      <small>첫 견적이거나 품목명이 달라요.</small>
                    </>
                  )}
                </div>
              </div>
              <details className="itemOptionalDetails">
                <summary>규격·메모·옵션</summary>
                <div className="itemReviewFields">
                  <input value={entry.spec} onChange={(event) => onUpdate(index, "spec", event.target.value)} placeholder="규격 예: 1kg, 대, 국내산" />
                  <input value={entry.memo} onChange={(event) => onUpdate(index, "memo", event.target.value)} placeholder="메모 예: 상태 좋은 상품 선호" />
                </div>
                <div className="itemReviewMeta">
                  <Toggle checked={entry.is_required ?? true} label="필수" onChange={(checked) => onUpdate(index, "is_required", checked)} />
                  <Toggle checked={entry.allow_alternative ?? true} label="대체 가능" onChange={(checked) => onUpdate(index, "allow_alternative", checked)} />
                  <span>인식률 {entry.confidence_score ?? 96}%</span>
                  {entry.review_reason && <small>{entry.review_reason}</small>}
                </div>
              </details>
            </div>
          </article>
        );
      })}
    </div>
  );
}

function AttachmentStatusList({ attachments }: { attachments: Array<Pick<QuoteAttachmentDraft, "file_name" | "file_type" | "analysis_status" | "extracted_text">> }) {
  if (attachments.length === 0) {
    return <p className="mutedText">첨부된 파일이 없습니다.</p>;
  }

  return (
    <div className="attachmentStatusList">
      {attachments.map((attachment, index) => (
        <div className="attachmentStatusCard" key={`${attachment.file_name}-${index}`}>
          <strong>{attachment.file_name}</strong>
          <span>{attachment.file_type.toUpperCase()} · {analysisStatusLabel(attachment.analysis_status)}</span>
          {attachment.extracted_text && <small>{attachment.extracted_text}</small>}
        </div>
      ))}
    </div>
  );
}

function StatList({ title, items }: { title: string; items: Array<{ label: string; value: number }> }) {
  return (
    <section className="statList">
      <h2>{title}</h2>
      {items.map((item) => (
        <div className="statRow" key={item.label}>
          <span>{item.label}</span>
          <strong>{item.value}건</strong>
        </div>
      ))}
    </section>
  );
}

function MoneyStatList({ title, items, secondaryLabel }: { title: string; items: Array<{ label: string; value: number; amount?: number }>; secondaryLabel?: string }) {
  return (
    <section className="statList">
      <h2>{title}</h2>
      {items.length === 0 && <p className="mutedText">표시할 데이터가 없습니다.</p>}
      {items.map((item) => (
        <div className="statRow" key={item.label}>
          <span>{item.label}</span>
          <strong>{money(item.value)}</strong>
          {typeof item.amount === "number" && <small>{secondaryLabel ?? "거래액"} {money(item.amount)}</small>}
        </div>
      ))}
    </section>
  );
}

function UsageLimitNotice({ data, supplierId, navigate }: { data: AppData; supplierId: string; navigate: Navigate }) {
  const gate = canSubmitQuoteByPlan(data, supplierId);
  if (SUPPLIER_BETA_FREE_ENABLED) {
    const plannedLimitText = gate.limit <= 0 ? "정식 플랜 기준 무제한" : `정식 플랜 기준 월 ${gate.limit}건`;
    return (
      <section className="usageNotice ok">
        <div>
          <span className="eyebrow">베타 무료 사용량</span>
          <h2>현재 견적 참여는 제한 없이 이용할 수 있습니다.</h2>
          <p>이번 달 {gate.usage.quotes_submitted_count}건을 사용했습니다. {plannedLimitText} 한도는 정식 출시 전환 준비용으로만 표시됩니다.</p>
          {gate.limit > 0 && <div className="usageBar"><span style={{ width: `${Math.min(100, Math.round((gate.usage.quotes_submitted_count / gate.limit) * 100))}%` }} /></div>}
        </div>
        <button className="secondaryButton" type="button" onClick={() => navigate("/app/supplier/billing")}>구독 준비 보기</button>
      </section>
    );
  }
  if (gate.limit <= 0) {
    return (
      <section className="usageNotice ok">
        <div>
          <span className="eyebrow">견적 참여 한도</span>
          <h2>현재 {gate.plan.name} 플랜은 견적 참여가 무제한입니다.</h2>
          <p>상위노출과 통계 제공 상태는 요금제 설정에 따라 샘플로 표시됩니다.</p>
        </div>
      </section>
    );
  }
  const ratio = Math.min(100, Math.round((gate.usage.quotes_submitted_count / gate.limit) * 100));
  return (
    <section className={gate.allowed ? "usageNotice" : "usageNotice blocked"}>
      <div>
        <span className="eyebrow">견적 참여 한도</span>
        <h2>{gate.allowed ? `이번 달 ${gate.limit}건 중 ${gate.usage.quotes_submitted_count}건을 사용했습니다.` : "이번 달 무료 견적 참여 한도를 모두 사용했습니다."}</h2>
        <p>{gate.allowed ? `남은 참여 가능 건수는 ${gate.remaining}건입니다.` : "더 많은 견적요청에 참여하려면 요금제를 업그레이드하거나 다음 달 초기화를 기다려주세요."}</p>
        <div className="usageBar"><span style={{ width: `${ratio}%` }} /></div>
      </div>
      {!gate.allowed && <button className="primaryButton" type="button" onClick={() => navigate("/app/supplier/billing")}>요금제 보기</button>}
    </section>
  );
}

function PlanCard({ plan }: { plan: SupplierPlan }) {
  return (
    <article className="planCard planCardPrivate">
      <div>
        <h3>{plan.name}</h3>
      </div>
      <p>세부 조건과 가격은 정식 출시 전까지 비공개입니다.</p>
    </article>
  );
}

function QuoteItemComparisonTable({ data, quotes, items }: { data: AppData; quotes: Quote[]; items: QuoteRequestItem[] }) {
  if (!quotes.length || !items.length) return null;

  return (
    <section className="toolPanel quoteItemPanel">
      <div className="itemComparisonHeader">
        <div>
          <span className="eyebrow">품목 확인</span>
          <h2>요청 품목 {items.length}개를 업체별로 확인하세요.</h2>
          <p>품목별 단가가 따로 없으면 업체의 단가 메모를 기준으로 표시합니다.</p>
        </div>
        <strong>{quotes.length}개 견적</strong>
      </div>
      <div className="requestedItemStrip" aria-label="요청 품목">
        {items.map((item) => (
          <span key={item.id}>
            <b>{item.item_name}</b>
            <small>{item.quantity.toLocaleString()} {item.unit}</small>
          </span>
        ))}
      </div>
      <div className="supplierItemSummaryList" aria-label="업체별 품목 확인 요약">
        {quotes.map((quote) => {
          const missingItemCount = quoteMissingItemCount(quote, items);
          const memo = quote.item_price_memo.trim();
          return (
            <article className="supplierItemSummary" key={quote.id}>
              <div className="supplierItemTop">
                <div>
                  <strong>{supplierName(data, quote.supplier_id)}</strong>
                  <span>{money(quote.final_amount)} · 납품 {quote.available_delivery_date}</span>
                </div>
                <StatusBadge tone={missingItemCount > 0 ? "orange" : "green"}>
                  {missingItemCount > 0 ? `${missingItemCount}개 확인` : "품목 확인됨"}
                </StatusBadge>
              </div>
              <div className="supplierItemMemo">
                <span>단가 메모</span>
                <p title={memo || undefined}>{memo || "업체 문의 필요"}</p>
              </div>
              <div className="supplierItemFacts">
                <span>배송 {quote.delivery_fee > 0 ? money(quote.delivery_fee) : "포함"}</span>
                <span>세금계산서 {yesNo(quote.tax_invoice_available)}</span>
                <span>카드 {yesNo(quote.card_payment_available)}</span>
              </div>
            </article>
          );
        })}
      </div>
      <details className="itemComparisonDetails">
        <summary>상세 표 보기</summary>
        <div className="tableWrap">
          <table>
            <thead>
              <tr>
                <th>품목</th>
                {quotes.map((quote) => <th key={quote.id}>{supplierName(data, quote.supplier_id)}</th>)}
              </tr>
            </thead>
            <tbody>
              {items.map((item) => (
                <tr key={item.id}>
                  <td>{item.item_name}</td>
                  {quotes.map((quote) => (
                    <td key={`${item.id}-${quote.id}`}>{quoteItemComparisonText(quote)}</td>
                  ))}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </details>
    </section>
  );
}

function QuoteComparisonSummary({ data, quotes, items, recommended, cheapest, fastest }: {
  data: AppData;
  quotes: Quote[];
  items: QuoteRequestItem[];
  recommended: Quote | null;
  cheapest: Quote | null;
  fastest: Quote | null;
}) {
  const taxReady = quotes.find((quote) => quote.tax_invoice_available);
  const cardReady = quotes.find((quote) => quote.card_payment_available);
  const summaryItems = [
    {
      label: "추천 견적",
      value: recommended ? supplierName(data, recommended.supplier_id) : "대기",
      desc: recommended ? `${money(recommended.final_amount)} · 품목 ${quoteMissingItemCount(recommended, items) > 0 ? "확인 필요" : "확인됨"}` : "견적 도착 후 표시",
      tone: "blue",
    },
    {
      label: "최저가",
      value: cheapest ? money(cheapest.final_amount) : "대기",
      desc: cheapest ? supplierName(data, cheapest.supplier_id) : "가격 비교 전",
      tone: "green",
    },
    {
      label: "빠른 납품",
      value: fastest ? fastest.available_delivery_date : "대기",
      desc: fastest ? supplierName(data, fastest.supplier_id) : "납품일 비교 전",
      tone: "orange",
    },
    {
      label: "세금계산서",
      value: taxReady ? "가능" : "확인 필요",
      desc: taxReady ? supplierName(data, taxReady.supplier_id) : "업체 문의 필요",
      tone: "green",
    },
    {
      label: "카드결제",
      value: cardReady ? "가능" : "확인 필요",
      desc: cardReady ? supplierName(data, cardReady.supplier_id) : "업체 문의 필요",
      tone: "blue",
    },
  ];

  return (
    <section className="quoteSummaryStrip" aria-label="견적 비교 요약">
      {summaryItems.map((item) => (
        <article className={`quoteSummaryCard ${item.tone}`} key={item.label}>
          <span>{item.label}</span>
          <strong>{item.value}</strong>
          <small>{item.desc}</small>
        </article>
      ))}
    </section>
  );
}

function QuoteCard({ data, quote, requestItems, isRecommended, isCheapest, isFastest, isSelected, isRejected, onSelect, onAskSupplier }: {
  data: AppData;
  quote: Quote;
  requestItems: QuoteRequestItem[];
  isRecommended: boolean;
  isCheapest: boolean;
  isFastest: boolean;
  isSelected: boolean;
  isRejected: boolean;
  onSelect: () => void;
  onAskSupplier: () => void;
}) {
  const supplier = data.supplier_profiles.find((entry) => entry.id === quote.supplier_id);
  const stats = supplier ? supplierStatsFor(data, supplier.id) : null;
  const documents = supplier ? data.supplier_documents.filter((document) => document.supplier_id === supplier.id) : [];
  const missingItemCount = quoteMissingItemCount(quote, requestItems);
  const badges = [
    isSelected ? { tone: "green" as const, label: "선택됨" } : null,
    isRecommended ? { tone: "blue" as const, label: "추천" } : null,
    isCheapest ? { tone: "green" as const, label: "최저가" } : null,
    isFastest ? { tone: "blue" as const, label: "빠른 납품" } : null,
    missingItemCount > 0 ? { tone: "orange" as const, label: "품목 확인" } : null,
    isRejected ? { tone: "gray" as const, label: "미선택" } : null,
  ].filter((badge): badge is { tone: "orange" | "blue" | "green" | "gray"; label: string } => Boolean(badge));
  const capabilityLabels = [
    quote.tax_invoice_available ? "세금계산서" : null,
    quote.card_payment_available ? "카드결제" : null,
    supplier?.urgent_delivery_available ? "긴급배송" : null,
    documents.some((document) => document.status === "approved") ? "인증자료" : null,
  ].filter((label): label is string => Boolean(label));
  const responseLabel = stats?.average_response_minutes ? `${stats.average_response_minutes}분` : "신규";
  return (
    <article className={isSelected ? "quoteCard selected" : "quoteCard"}>
      <div className="quoteHeader">
        <div>
          <span className="eyebrow">공급업체</span>
          <h3>{supplierName(data, quote.supplier_id)}</h3>
        </div>
        <div className="quoteBadges" aria-label="견적 특징">
          {badges.map((badge) => <StatusBadge tone={badge.tone} key={badge.label}>{badge.label}</StatusBadge>)}
        </div>
      </div>
      {supplier && (
        <div className="quoteTrustSummary">
          <div className="quoteTrustIntro">
            <strong>승인 공급업체</strong>
            <span>{capabilityLabels.length ? capabilityLabels.join(" · ") : "기본 조건 확인 필요"}</span>
          </div>
          <div className="quoteTrustMetrics" aria-label="공급업체 신뢰 요약">
            <span><b>{stats?.rating ? stats.rating.toFixed(1) : "신규"}</b><small>평점</small></span>
            <span><b>{responseLabel}</b><small>응답</small></span>
            <span><b>{stats?.selected_quotes_count ?? 0}건</b><small>거래</small></span>
          </div>
        </div>
      )}
      <div className="priceBlock quotePricePanel">
        <span className="quotePriceLabel">최종 견적가</span>
        <strong>{money(quote.final_amount)}</strong>
        <div className="quoteAmountBreakdown">
          <span>상품 {money(quote.total_amount)}</span>
          <span>배송 {quote.delivery_fee > 0 ? money(quote.delivery_fee) : "포함"}</span>
        </div>
      </div>
      <div className="quoteFacts quoteKeyFacts" aria-label="견적 핵심 조건">
        <span className={isFastest ? "fact strong" : "fact"}><small>납품</small>{quote.available_delivery_date}</span>
        <span className="fact"><small>배송비</small>{quote.delivery_fee > 0 ? "별도" : "포함"}</span>
        <span className="fact"><small>세금</small>{yesNo(quote.tax_invoice_available)}</span>
        <span className="fact"><small>카드</small>{yesNo(quote.card_payment_available)}</span>
        <span className={missingItemCount > 0 ? "fact strong" : "fact"}><small>품목</small>{missingItemCount > 0 ? `${missingItemCount}개 확인` : "확인됨"}</span>
      </div>
      <dl className="quoteDetails quoteMemoGrid">
        <div>
          <dt>단가 메모</dt>
          <dd title={quote.item_price_memo || undefined}>{quote.item_price_memo || "미입력"}</dd>
        </div>
        <div>
          <dt>업체 메모</dt>
          <dd title={quote.memo || undefined}>{quote.memo || "미입력"}</dd>
        </div>
        <div>
          <dt>유효기간</dt>
          <dd>{quote.valid_until}</dd>
        </div>
      </dl>
      {quote.alternative_proposal && <p className="proposal">{quote.alternative_proposal}</p>}
      <div className="quoteActions">
        <button className="secondaryButton full" type="button" onClick={onAskSupplier}>
          <MessageCircle size={17} />
          문의하기
        </button>
        <button className={isSelected ? "selectedButton full" : "primaryButton full"} type="button" onClick={onSelect} disabled={isSelected}>
          <Check size={17} />
          {isSelected ? "선택된 견적" : "이 업체 선택"}
        </button>
      </div>
    </article>
  );
}

function DealNotice({ data, deal, quote, onOpen }: { data: AppData; deal: Deal; quote: Quote; onOpen: () => void }) {
  return (
    <section className="dealNotice">
      <div>
        <span className="eyebrow">선택된 거래</span>
        <h2>{supplierName(data, quote.supplier_id)} 견적으로 거래가 생성되었습니다.</h2>
        <p>거래 상태: {dealStatusLabels[deal.status]} · 최종금액 {money(deal.final_amount)}</p>
      </div>
      <button className="primaryButton" type="button" onClick={onOpen}>
        거래 상세보기
        <ArrowRight size={16} />
      </button>
    </section>
  );
}

function QuoteConfirmModal({ data, quote, onCancel, onConfirm }: { data: AppData; quote: Quote; onCancel: () => void; onConfirm: () => void }) {
  return (
    <div className="modalBackdrop" role="dialog" aria-modal="true" aria-labelledby="quote-confirm-title">
      <section className="modalPanel">
        <h2 id="quote-confirm-title">이 견적으로 거래를 진행할까요?</h2>
        <div className="confirmGrid">
          <span>공급업체명</span><strong>{supplierName(data, quote.supplier_id)}</strong>
          <span>총 견적금액</span><strong>{money(quote.total_amount)}</strong>
          <span>배송비</span><strong>{money(quote.delivery_fee)}</strong>
          <span>최종금액</span><strong>{money(quote.final_amount)}</strong>
          <span>납품 가능일</span><strong>{quote.available_delivery_date}</strong>
          <span>세금계산서</span><strong>{yesNo(quote.tax_invoice_available)}</strong>
          <span>카드결제</span><strong>{yesNo(quote.card_payment_available)}</strong>
          <span>대체품 제안</span><strong>{quote.alternative_proposal || "없음"}</strong>
          <span>견적 유효기간</span><strong>{quote.valid_until}</strong>
        </div>
        <div className="safeTradeChoice">
          <span><ShieldCheck size={17} /> 싸와 안심거래 추천</span>
          <p>첫 거래나 고액 거래는 안심거래로 진행하면 구매자와 공급업체 모두 거래 상태를 확인하기 쉽습니다.</p>
        </div>
        <p className="modalGuide">업체를 선택하면 거래가 생성됩니다. 결제 방식은 거래 화면에서 선택합니다.</p>
        <div className="formActions">
          <button className="secondaryButton" type="button" onClick={onCancel}>취소</button>
          <button className="primaryButton" type="button" onClick={onConfirm}>
            <Check size={17} />
            거래 진행하기
          </button>
        </div>
      </section>
    </div>
  );
}

function FilterTabs({ options, active, onChange }: { options: string[]; active: string; onChange: (option: string) => void }) {
  return (
    <div className="filterTabs">
      {options.map((option) => (
        <button className={active === option ? "filterTab active" : "filterTab"} type="button" onClick={() => onChange(option)} key={option}>
          {option}
        </button>
      ))}
    </div>
  );
}

function DealTable({ data, deals, navigate, basePath, role }: { data: AppData; deals: Deal[]; navigate: Navigate; basePath: string; role: "buyer" | "supplier" | "admin" }) {
  if (deals.length === 0) {
    return <EmptyState icon={<ReceiptText />} title="표시할 거래가 없습니다." desc="견적을 선택하면 거래가 생성됩니다." />;
  }

  return (
    <>
      <div className="tableWrap dealTableWrap">
        <table>
          <thead>
            <tr>
              <th>거래명</th>
              <th>{role === "buyer" ? "공급업체" : "구매자"}</th>
              <th>지역</th>
              <th>납품일</th>
              <th>최종금액</th>
              <th>상태</th>
              <th>생성일</th>
              <th>상세</th>
            </tr>
          </thead>
          <tbody>
            {deals.map((deal) => {
              const buyer = data.profiles.find((entry) => entry.id === deal.buyer_id);
              return (
                <tr key={deal.id} onClick={() => navigate(`${basePath}/${deal.id}`)}>
                  <td>{deal.title}</td>
                  <td>{role === "buyer" ? supplierName(data, deal.supplier_id) : buyer?.business_name ?? "구매자"}</td>
                  <td>{deal.delivery_region}</td>
                  <td>{deal.confirmed_delivery_date || deal.desired_delivery_date}</td>
                  <td>{money(deal.final_amount)}</td>
                  <td>
                    <StatusBadge tone={deal.status === "completed" ? "green" : deal.status === "disputed" ? "orange" : deal.status.includes("cancelled") ? "gray" : "blue"}>
                      {dealStatusLabels[deal.status]}
                    </StatusBadge>
                  </td>
                  <td>{deal.created_at.slice(0, 10)}</td>
                  <td>
                    <button className="ghostButton compact" type="button">상세보기</button>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
      <div className="dealMobileList" aria-label="모바일 거래 목록">
        {deals.map((deal) => {
          const buyer = data.profiles.find((entry) => entry.id === deal.buyer_id);
          const counterpart = role === "buyer" ? supplierName(data, deal.supplier_id) : buyer?.business_name ?? "구매자";
          return (
            <article className="dealMobileCard" key={deal.id}>
              <div className="dealMobileHeader">
                <div>
                  <span>{role === "buyer" ? "공급업체" : "구매자"} · {counterpart}</span>
                  <h3>{deal.title}</h3>
                </div>
                <StatusBadge tone={deal.status === "completed" ? "green" : deal.status === "disputed" ? "orange" : deal.status.includes("cancelled") ? "gray" : "blue"}>
                  {dealStatusLabels[deal.status]}
                </StatusBadge>
              </div>
              <div className="dealMobileFacts">
                <span><small>최종금액</small><strong>{money(deal.final_amount)}</strong></span>
                <span><small>납품일</small><strong>{deal.confirmed_delivery_date || deal.desired_delivery_date}</strong></span>
                <span><small>지역</small><strong>{deal.delivery_region}</strong></span>
              </div>
              <button className="primaryButton full" type="button" onClick={() => navigate(`${basePath}/${deal.id}`)}>
                거래 상세보기
              </button>
            </article>
          );
        })}
      </div>
    </>
  );
}

function DealStepper({ status }: { status: DealStatus }) {
  const steps: Array<{ key: DealStatus; label: string }> = [
    { key: "pending_confirmation", label: "견적 선택" },
    { key: "confirmed", label: "거래 확인" },
    { key: "preparing", label: "납품 준비" },
    { key: "delivering", label: "배송/납품" },
    { key: "completed", label: "거래 완료" },
  ];
  const activeIndex = status === "delivered" ? 4 : Math.max(0, steps.findIndex((step) => step.key === status));

  return (
    <div className="dealStepper">
      {steps.map((step, index) => (
        <div className={index <= activeIndex && !status.includes("cancelled") && status !== "disputed" ? "step active" : "step"} key={step.key}>
          <span>{index + 1}</span>
          <strong>{step.label}</strong>
        </div>
      ))}
    </div>
  );
}

function DealActions({
  deal,
  role,
  onChange,
  onCancel,
  onDispute,
  navigate,
  purchaseRecordId,
  reviewId,
}: {
  deal: Deal;
  role: "buyer" | "supplier" | "admin";
  onChange: (status: DealStatus, changedBy: "buyer" | "supplier" | "admin", memo: string) => void;
  onCancel: () => void;
  onDispute: () => void;
  navigate: Navigate;
  purchaseRecordId?: string;
  reviewId?: string;
}) {
  if (deal.status === "completed") {
    if (role === "supplier") {
      return (
        <div className="actionStack">
          <p className="mutedText">거래 완료됨</p>
          <button className="secondaryButton" type="button" onClick={() => navigate("/app/today/supplier/sales")}>매출내역 보기</button>
          <button className="ghostButton" type="button" onClick={() => navigate("/app/supplier/settlements")}>입금/증빙 확인</button>
        </div>
      );
    }

    if (role === "admin") {
      return (
        <div className="actionStack">
          <p className="mutedText">거래 완료됨</p>
          <button className="secondaryButton" type="button" onClick={() => navigate("/app/admin/deals")}>전체 거래 보기</button>
          <button className="ghostButton" type="button" onClick={() => navigate("/app/admin/settlements")}>정산 관리</button>
        </div>
      );
    }

    return (
      <div className="actionStack">
        <p className="mutedText">거래 완료됨</p>
        <button className="secondaryButton" type="button" onClick={() => purchaseRecordId && navigate(`/app/purchases/${purchaseRecordId}`)}>구매내역 보기</button>
        <button className="primaryButton" type="button" onClick={() => navigate("/app/requests/new")}>다시 견적요청하기</button>
        <button className="ghostButton" type="button" onClick={() => navigate(reviewId ? "/app/reviews" : `/app/deals/${deal.id}/review`)}>{reviewId ? "작성한 후기 보기" : "후기 작성"}</button>
        {purchaseRecordId && <p className="mutedText">구매내역 ID: {purchaseRecordId}</p>}
      </div>
    );
  }

  if (deal.status.includes("cancelled") || deal.status === "disputed") {
    return <p className="mutedText">현재 상태에서는 추가 진행 버튼을 제공하지 않습니다.</p>;
  }

  if (role === "supplier") {
    const supplierActions: Partial<Record<DealStatus, Array<{ label: string; next: DealStatus; memo: string }>>> = {
      pending_confirmation: [
        { label: "거래 수락", next: "confirmed", memo: "공급업체가 거래를 수락했습니다." },
        { label: "거래 거절", next: "cancelled_by_supplier", memo: "공급업체가 거래를 거절했습니다." },
      ],
      confirmed: [{ label: "납품 준비 시작", next: "preparing", memo: "납품 준비를 시작했습니다." }],
      preparing: [{ label: "배송/납품 시작", next: "delivering", memo: "배송/납품을 시작했습니다." }],
      delivering: [{ label: "납품 완료 처리", next: "delivered", memo: "납품 완료 처리했습니다." }],
    };
    return <ActionButtons actions={supplierActions[deal.status] ?? []} role="supplier" onChange={onChange} />;
  }

  if (role === "buyer") {
    const buyerActions: Partial<Record<DealStatus, Array<{ label: string; next: DealStatus; memo: string }>>> = {
      pending_confirmation: [{ label: "업체에 확인 요청 UI", next: "pending_confirmation", memo: "업체 확인을 요청했습니다." }],
      confirmed: [{ label: "납품 완료 확인", next: "delivered", memo: "구매자가 납품 완료를 확인했습니다." }],
      preparing: [{ label: "납품 완료 확인", next: "delivered", memo: "구매자가 납품 완료를 확인했습니다." }],
      delivering: [{ label: "납품 완료 확인", next: "delivered", memo: "구매자가 납품 완료를 확인했습니다." }],
      delivered: [{ label: "거래 완료하기", next: "completed", memo: "구매자가 거래 완료를 확정했습니다." }],
    };
    return (
      <div className="actionStack">
        <ActionButtons actions={buyerActions[deal.status] ?? []} role="buyer" onChange={onChange} />
        <button className="secondaryButton" type="button" onClick={onCancel}>거래 취소</button>
        <button className="ghostButton" type="button" onClick={onDispute}>문제 신고</button>
      </div>
    );
  }

  return (
    <div className="actionStack">
      <button className="secondaryButton" type="button" onClick={onDispute}>관리자 문제 표시</button>
      <button className="ghostButton" type="button">관리자 메모 UI</button>
    </div>
  );
}

function ActionButtons({ actions, role, onChange }: { actions: Array<{ label: string; next: DealStatus; memo: string }>; role: "buyer" | "supplier" | "admin"; onChange: (status: DealStatus, changedBy: "buyer" | "supplier" | "admin", memo: string) => void }) {
  return (
    <div className="actionStack">
      {actions.map((action) => (
        <button className="primaryButton" type="button" onClick={() => onChange(action.next, role, action.memo)} key={`${action.label}-${action.next}`}>
          {action.label}
        </button>
      ))}
    </div>
  );
}

function ReasonModal({
  mode,
  reason,
  memo,
  onReason,
  onMemo,
  onCancel,
  onSubmit,
}: {
  mode: "cancel" | "dispute";
  reason: string;
  memo: string;
  onReason: (value: string) => void;
  onMemo: (value: string) => void;
  onCancel: () => void;
  onSubmit: () => void;
}) {
  const reasons = mode === "cancel"
    ? ["일정 변경", "금액 조건 변경", "업체와 별도 협의", "품목 변경 필요", "잘못 선택함", "기타"]
    : ["납품 지연", "품목 누락", "수량 불일치", "품질 문제", "금액 불일치", "세금계산서 문제", "기타"];

  return (
    <div className="modalBackdrop" role="dialog" aria-modal="true">
      <section className="modalPanel">
        <h2>{mode === "cancel" ? "거래 취소" : "문제 신고"}</h2>
        <Field label={mode === "cancel" ? "취소 사유" : "문제 유형"}>
          <select value={reason} onChange={(event) => onReason(event.target.value)}>
            {reasons.map((entry) => <option key={entry}>{entry}</option>)}
          </select>
        </Field>
        <Field label="상세 내용">
          <textarea value={memo} onChange={(event) => onMemo(event.target.value)} placeholder="상세 내용을 입력하세요." />
        </Field>
        {mode === "dispute" && (
          <div className="uploadBox">
            <Upload size={20} />
            <input placeholder="첨부 사진 파일명" />
          </div>
        )}
        <div className="formActions">
          <button className="secondaryButton" type="button" onClick={onCancel}>취소</button>
          <button className="primaryButton" type="button" onClick={onSubmit}>확인</button>
        </div>
      </section>
    </div>
  );
}

function SavingsNotice({ savings, previousAmount }: { savings: { amount: number; rate: number }; previousAmount?: number }) {
  if (!previousAmount) {
    return <p className="mutedText">기존 거래가를 입력하면 절감액을 계산할 수 있습니다.</p>;
  }

  if (savings.amount <= 0) {
    return <p className="mutedText">기존 거래가 {money(previousAmount)} 기준 절감액이 아직 없습니다.</p>;
  }

  return <p className="savingText">기존 거래가 대비 약 {money(savings.amount)} 절감되었습니다. 절감률 {savings.rate}%</p>;
}

function Page({ children, narrow = false }: { children: ReactNode; narrow?: boolean }) {
  return <div className={narrow ? "page narrow" : "page"}>{children}</div>;
}

function PageTitle({ eyebrow, title, desc }: { eyebrow: string; title: string; desc: string }) {
  return (
    <section className="pageTitle">
      <span className="eyebrow">{eyebrow}</span>
      <h1>{title}</h1>
      <p>{desc}</p>
    </section>
  );
}

function SectionHeader({ title, action, onAction }: { title: string; action?: string; onAction?: () => void }) {
  return (
    <div className="sectionHeader">
      <h2>{title}</h2>
      {action && onAction && (
        <button className="ghostButton compact" type="button" onClick={onAction}>
          {action}
          <ArrowRight size={15} />
        </button>
      )}
    </div>
  );
}

function RegionSearchField({
  value,
  onChange,
  required = false,
  selectionOnly = false,
  placeholder = "지역명 검색: 서울 강남구",
}: {
  value: string;
  onChange: (value: string) => void;
  required?: boolean;
  selectionOnly?: boolean;
  placeholder?: string;
}) {
  const [query, setQuery] = useState(value);
  const [open, setOpen] = useState(false);
  const normalizedQuery = query.trim().replace(/\s+/g, " ");
  const suggestions = useMemo(() => {
    if (!normalizedQuery) return KOREA_REGION_OPTIONS.slice(0, 12);
    return KOREA_REGION_OPTIONS
      .filter((region) => region.includes(normalizedQuery) || region.replace(/\s+/g, "").includes(normalizedQuery.replace(/\s+/g, "")))
      .slice(0, 12);
  }, [normalizedQuery]);

  useEffect(() => {
    setQuery(value);
  }, [value]);

  function selectRegion(region: string) {
    setQuery(region);
    onChange(region);
    setOpen(false);
  }

  function updateQuery(nextQuery: string) {
    setQuery(nextQuery);
    if (selectionOnly) {
      const exactRegion = KOREA_REGION_OPTIONS.find((region) => region === nextQuery.trim());
      onChange(exactRegion ?? "");
    } else {
      onChange(nextQuery);
    }
    setOpen(true);
  }

  function handleBlur() {
    window.setTimeout(() => {
      setOpen(false);
      if (selectionOnly && query.trim() && !isKoreaRegionOption(query)) {
        setQuery(value);
      }
    }, 140);
  }

  return (
    <div className="regionSearchField">
      <input
        value={query}
        onChange={(event) => updateQuery(event.target.value)}
        onFocus={() => setOpen(true)}
        onBlur={handleBlur}
        onKeyDown={(event) => {
          if (event.key === "Enter" && suggestions[0]) {
            event.preventDefault();
            selectRegion(suggestions[0]);
          }
        }}
        required={required}
        placeholder={placeholder}
        autoComplete="address-level2"
      />
      {open && suggestions.length > 0 && (
        <div className="regionSuggestionList" role="listbox" aria-label="대한민국 지역 선택">
          {suggestions.map((region) => (
            <button type="button" role="option" onMouseDown={(event) => event.preventDefault()} onClick={() => selectRegion(region)} key={region}>
              {region}
            </button>
          ))}
        </div>
      )}
    </div>
  );
}

function SupplierRegionSelector({ regions, onChange }: { regions: string[]; onChange: (regions: string[]) => void }) {
  const [query, setQuery] = useState("");
  const normalizedQuery = query.trim().replace(/\s+/g, " ");
  const compactQuery = normalizedQuery.replace(/\s+/g, "");
  const selectedRegions = Array.from(new Set(regions.filter(Boolean)));
  const suggestions = useMemo(() => {
    if (!normalizedQuery) return [];
    return KOREA_REGION_OPTIONS
      .filter((region) => !selectedRegions.includes(region))
      .filter((region) => region.includes(normalizedQuery) || region.replace(/\s+/g, "").includes(compactQuery))
      .slice(0, 12);
  }, [compactQuery, normalizedQuery, selectedRegions]);

  function addRegion(region: string) {
    onChange([...selectedRegions, region]);
    setQuery("");
  }

  function removeRegion(region: string) {
    onChange(selectedRegions.filter((entry) => entry !== region));
  }

  return (
    <div className="supplierRegionSelector">
      <div className="supplierRegionSearchPanel">
        <div className="supplierRegionPanelHeader">
          <div>
            <strong>지역명으로 검색</strong>
            <span>시/군/구 단위로 검색해서 추가하세요.</span>
          </div>
          <span className="supplierRegionCount">{selectedRegions.length}개 선택</span>
        </div>
        <div className="supplierRegionInputRow">
          <span className="supplierRegionInputPrefix">검색</span>
          <input
            value={query}
            onChange={(event) => setQuery(event.target.value)}
            onKeyDown={(event) => {
              if (event.key === "Enter" && suggestions[0]) {
                event.preventDefault();
                addRegion(suggestions[0]);
              }
            }}
            placeholder="예: 서울 강남구, 경기 성남시"
            autoComplete="address-level2"
          />
          {query && <button className="supplierRegionClearButton" type="button" onClick={() => setQuery("")}>지우기</button>}
        </div>
        <div className={normalizedQuery ? "supplierRegionResults active" : "supplierRegionResults"}>
          {!normalizedQuery && <span>검색어를 입력하면 저장된 대한민국 지역 목록에서 결과가 표시됩니다.</span>}
          {normalizedQuery && suggestions.length === 0 && <span>검색 결과가 없습니다. 다른 지역명으로 입력해 주세요.</span>}
          {suggestions.map((region) => (
            <button type="button" onClick={() => addRegion(region)} key={region}>
              <span>{region}</span>
              <strong>추가</strong>
            </button>
          ))}
        </div>
      </div>
      <div className="supplierSelectedRegionPanel">
        <div className="supplierSelectedRegionHeader">
          <strong>선택된 납품 가능 지역</strong>
          {selectedRegions.length > 0 && <button type="button" onClick={() => onChange([])}>전체 삭제</button>}
        </div>
        {selectedRegions.length > 0 ? (
          <div className="supplierSelectedRegionGrid" aria-label="선택된 납품 가능 지역">
            {selectedRegions.map((region) => (
              <button type="button" onClick={() => removeRegion(region)} key={region}>
                <span>{region}</span>
                <strong aria-hidden="true">×</strong>
              </button>
            ))}
          </div>
        ) : (
          <div className="supplierRegionEmptyState">
            아직 선택된 지역이 없습니다.
          </div>
        )}
      </div>
    </div>
  );
}

function KakaoPostcodeLayer({ open, onClose, onSelect }: { open: boolean; onClose: () => void; onSelect: (result: KakaoPostcodeResult) => void }) {
  const containerRef = useRef<HTMLDivElement | null>(null);
  const [status, setStatus] = useState("");

  useEffect(() => {
    if (!open) return;
    let cancelled = false;
    setStatus("주소 검색을 불러오는 중입니다.");
    loadKakaoPostcodeScript()
      .then(() => {
        const Postcode = getKakaoPostcodeConstructor();
        if (cancelled || !containerRef.current || !Postcode) return;
        containerRef.current.innerHTML = "";
        const postcode = new Postcode({
          width: "100%",
          height: "100%",
          maxSuggestItems: 5,
          onresize: (size) => {
            if (containerRef.current) containerRef.current.style.height = `${Math.max(size.height, 460)}px`;
          },
          oncomplete: (data) => {
            const address = data.userSelectedType === "R" ? data.roadAddress || data.address : data.jibunAddress || data.address;
            onSelect({
              address,
              zonecode: data.zonecode,
              region: formatKakaoRegion(data),
            });
            onClose();
          },
        });
        postcode.embed(containerRef.current);
        setStatus("");
      })
      .catch(() => {
        if (!cancelled) setStatus("주소 검색을 불러오지 못했습니다. 잠시 후 다시 시도하거나 주소를 직접 입력해 주세요.");
      });
    return () => {
      cancelled = true;
    };
  }, [open, onClose, onSelect]);

  if (!open) return null;

  return (
    <div className="postcodeLayerBackdrop" role="dialog" aria-modal="true" aria-label="사업장 주소 검색">
      <div className="postcodeLayerPanel">
        <div className="postcodeLayerHeader">
          <strong>사업장 주소 검색</strong>
          <button className="ghostButton compact" type="button" onClick={onClose}>닫기</button>
        </div>
        <p className="postcodeLayerGuide">도로명, 건물명, 지번 주소를 검색한 뒤 사업장 주소를 선택해 주세요.</p>
        {status && <p className="postcodeLayerStatus">{status}</p>}
        <div className="postcodeLayerFrame" ref={containerRef} />
      </div>
    </div>
  );
}

