async function fetchWithTimeout(input: RequestInfo | URL, init: RequestInit = {}, timeoutMs = 35000) {
  const controller = new AbortController();
  const timer = window.setTimeout(() => controller.abort(), timeoutMs);
  try {
    return await fetch(input, { ...init, signal: controller.signal });
  } catch (error) {
    if ((error as Error)?.name === "AbortError") {
      throw new Error("AI 분석 응답이 지연되고 있습니다.");
    }
    throw error;
  } finally {
    window.clearTimeout(timer);
  }
}

function normalizeReceiptPreviewForToday(preview: ReceiptAnalysisPreview): TodayAiPurchaseDraft {
  const category = normalizeTodayPurchaseCategoryName(preview.categoryName);
  const evenAmount = preview.items.length && preview.totalAmount > 0 ? Math.round(preview.totalAmount / preview.items.length) : 0;
  const items = preview.items.map((item) => {
    const amount = findMoneyMentions(item.memo).pop() ?? evenAmount;
    return {
      item_name: item.item_name,
      spec: item.spec,
      quantity: item.quantity,
      unit: item.unit,
      unit_price: item.quantity > 0 && amount > 0 ? Math.round(amount / item.quantity) : amount,
      total_price: amount,
      memo: item.memo,
      confidence_score: item.confidence_score,
      needs_review: item.needs_review || amount <= 0,
      review_reason: item.review_reason || (amount <= 0 ? "금액을 직접 확인해 주세요." : ""),
    } satisfies TodayAiPurchaseItemDraft;
  });
  return {
    source: "receipt",
    raw_text: preview.rawText,
    confidence_score: preview.confidenceScore,
    purchase_title: `${items[0]?.item_name ?? "영수증"} 외 ${Math.max(0, items.length - 1)}건`,
    supplier_name: preview.supplierName || "이미지 영수증",
    supplier_business_number: "000-00-00000",
    purchase_date: today,
    category_name: category,
    accounting_category: category,
    sub_category: "",
    total_amount: preview.totalAmount || items.reduce((sum, item) => sum + item.total_price, 0),
    supply_amount: 0,
    vat_amount: 0,
    delivery_fee: 0,
    discount_amount: 0,
    payment_method: "undecided",
    tax_invoice_status: "none",
    receipt_status: "uploaded",
    delivery_note_status: "none",
    memo: `이미지 영수증 자동 입력: ${preview.fileName}\n${preview.rawText}`,
    items,
  };
}

function readFileAsBase64(file: File): Promise<string> {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => {
      const result = String(reader.result ?? "");
      resolve(result.includes(",") ? result.split(",").pop() ?? "" : result);
    };
    reader.onerror = () => reject(new Error("이미지를 읽지 못했습니다."));
    reader.readAsDataURL(file);
  });
}

async function readReceiptImageForAnalysis(file: File, fileName: string) {
  const mimeType = inferReceiptImageMimeType(file, fileName || file.name) || "image/jpeg";
  const optimized = await optimizeReceiptImageForAnalysis(file).catch(() => null);
  if (optimized) {
    return {
      fileName: normalizedReceiptImageFileName(fileName, "jpg"),
      mimeType: "image/jpeg",
      imageBase64: optimized,
      optimized: true,
    };
  }
  return {
    fileName,
    mimeType,
    imageBase64: await readFileAsBase64(file),
    optimized: false,
  };
}

function inferReceiptImageMimeType(file: File, fileName: string) {
  const explicitType = file.type.trim().toLowerCase();
  if (explicitType.startsWith("image/")) return explicitType;
  const name = `${fileName || file.name || ""}`.toLowerCase();
  if (/\.(jpe?g|jfif)$/.test(name)) return "image/jpeg";
  if (/\.png$/.test(name)) return "image/png";
  if (/\.webp$/.test(name)) return "image/webp";
  if (/\.gif$/.test(name)) return "image/gif";
  if (/\.heic$/.test(name)) return "image/heic";
  if (/\.heif$/.test(name)) return "image/heif";
  if (!explicitType || explicitType === "application/octet-stream") return "image/jpeg";
  return "";
}

function optimizeReceiptImageForAnalysis(file: File): Promise<string | null> {
  if (typeof document === "undefined" || typeof URL === "undefined") return Promise.resolve(null);
  return new Promise((resolve) => {
    const image = new Image();
    const objectUrl = URL.createObjectURL(file);
    image.onload = () => {
      try {
        const width = image.naturalWidth || image.width;
        const height = image.naturalHeight || image.height;
        if (!width || !height) {
          resolve(null);
          return;
        }
        const maxSide = 2200;
        const scale = Math.min(1, maxSide / Math.max(width, height));
        const targetWidth = Math.max(1, Math.round(width * scale));
        const targetHeight = Math.max(1, Math.round(height * scale));
        const canvas = document.createElement("canvas");
        canvas.width = targetWidth;
        canvas.height = targetHeight;
        const context = canvas.getContext("2d", { alpha: false });
        if (!context) {
          resolve(null);
          return;
        }
        context.fillStyle = "#ffffff";
        context.fillRect(0, 0, targetWidth, targetHeight);
        context.imageSmoothingEnabled = true;
        context.imageSmoothingQuality = "high";
        context.drawImage(image, 0, 0, targetWidth, targetHeight);
        canvas.toBlob((blob) => {
          if (!blob) {
            resolve(null);
            return;
          }
          readFileAsBase64(new File([blob], "receipt-analysis.jpg", { type: "image/jpeg" }))
            .then((base64) => resolve(base64))
            .catch(() => resolve(null));
        }, "image/jpeg", 0.9);
      } catch {
        resolve(null);
      } finally {
        URL.revokeObjectURL(objectUrl);
      }
    };
    image.onerror = () => {
      URL.revokeObjectURL(objectUrl);
      resolve(null);
    };
    image.src = objectUrl;
  });
}

function normalizedReceiptImageFileName(fileName: string, extension: string) {
  const safeName = (fileName || "receipt-image").replace(/\.[^.]+$/, "").trim() || "receipt-image";
  return `${safeName}.${extension}`;
}

function normalizeGeminiReceiptPayload(payload: Record<string, unknown>, fileName: string, sourceType: "photo" | "invoice", mimeType: string): ReceiptAnalysisPreview {
  const rawItems = Array.isArray(payload.items) ? payload.items : [];
  const items = rawItems.slice(0, 20).map((entry) => {
    const item = entry && typeof entry === "object" ? entry as Record<string, unknown> : {};
    const name = stringValue(item.itemName) || stringValue(item.item_name) || "품목명 확인 필요";
    const quantity = positiveNumber(item.quantity, 1);
    const unit = stringValue(item.unit) || "개";
    const confidence = clampScore(positiveNumber(item.confidenceScore, positiveNumber(payload.confidenceScore, 82)));
    return {
      item_name: name,
      spec: stringValue(item.spec),
      quantity,
      unit,
      memo: stringValue(item.memo) || (positiveNumber(item.unitPrice, 0) ? `이전 구매 단가 ${money(positiveNumber(item.unitPrice, 0))}` : ""),
      is_required: true,
      allow_alternative: true,
      confidence_score: confidence,
      needs_review: Boolean(item.needsReview) || confidence < 75,
      review_reason: stringValue(item.reviewReason) || (confidence < 75 ? "AI 인식 신뢰도가 낮아 확인이 필요합니다." : ""),
    };
  });
  const normalizedItems = items.length ? items : [{ ...emptyItem, item_name: "품목명 확인 필요", confidence_score: 55, needs_review: true, review_reason: "이미지에서 품목을 충분히 인식하지 못했습니다." }];
  const supplierName = stringValue(payload.supplierName) || "업로드 이미지";
  const categoryName = stringValue(payload.categoryName) || "기타";
  const totalAmount = positiveNumber(payload.totalAmount, 0);
  const confidenceScore = clampScore(positiveNumber(payload.confidenceScore, 82));
  const rawText = stringValue(payload.rawText) || normalizedItems.map((item) => `${item.item_name} ${item.quantity}${item.unit}`).join("\n");
  return {
    fileName,
    sourceType,
    supplierName,
    categoryName,
    confidenceScore,
    totalAmount,
    rawText,
    attachment: {
      file_name: fileName,
      file_type: fileName.split(".").pop() || mimeType.split("/").pop() || "jpg",
      analysis_status: "analyzed",
      extracted_text: `AI가 ${normalizedItems.length}개 품목을 추출했습니다.`,
      extracted_items_json: JSON.stringify({ source: "gemini", ...payload, normalizedItems }),
    },
    items: normalizedItems,
  };
}

function stringValue(value: unknown) {
  return typeof value === "string" ? value.trim() : "";
}

function positiveNumber(value: unknown, fallback: number) {
  const numeric = typeof value === "number" ? value : typeof value === "string" ? Number(value.replace(/,/g, "")) : NaN;
  return Number.isFinite(numeric) && numeric >= 0 ? numeric : fallback;
}

function clampScore(value: number) {
  return Math.max(30, Math.min(99, Math.round(value)));
}

function errorMessage(error: unknown) {
  return error instanceof Error ? error.message : "알 수 없는 오류가 발생했습니다.";
}

function formatGeminiAnalysisError(error: unknown) {
  const rawMessage = errorMessage(error);
  const message = neutralizeAiProviderMessage(rawMessage);
  if (rawMessage.includes("GEMINI_API_KEY") || rawMessage.includes("OAuth") || rawMessage.includes("API 키")) {
    return `AI 분석 설정 필요: ${message}`;
  }
  if (isTemporaryGeminiDemandError(rawMessage)) {
    return "AI 분석 요청이 잠시 몰려 분석이 지연되고 있습니다. 1~2분 뒤 다시 'AI로 자동 입력'을 눌러 주세요. 급하면 아래 품목을 직접 입력해 견적요청을 계속 진행할 수 있습니다.";
  }
  if (/failed to fetch|network|load failed|internet|연결/i.test(rawMessage)) {
    return "AI 분석 서버와 연결하지 못했습니다. 모바일 데이터 또는 와이파이 연결을 확인한 뒤 다시 눌러 주세요.";
  }
  return `AI 분석 연결 실패: ${message}`;
}

function neutralizeAiProviderMessage(message: string) {
  return message
    .replace(/Gemini AI/gi, "AI 분석 서비스")
    .replace(/Gemini API/gi, "AI 분석 API")
    .replace(/Gemini/gi, "AI 분석 서비스")
    .replace(/Google AI Studio/gi, "AI 키 발급 페이지")
    .replace(/GEMINI_API_KEY/g, "이미지 AI 분석용 서버 키");
}

function isTemporaryGeminiDemandError(message: string) {
  const text = message.toLowerCase();
  return text.includes("high demand")
    || text.includes("try again later")
    || text.includes("temporarily unavailable")
    || text.includes("overloaded")
    || text.includes("resource exhausted")
    || text.includes("rate limit")
    || text.includes("사용량이 잠시 많아")
    || text.includes("분석이 지연");
}

function money(value: number) {
  return new Intl.NumberFormat("ko-KR", { style: "currency", currency: "KRW", maximumFractionDigits: 0 }).format(value);
}

function compactKrw(value: number) {
  const amount = Math.max(0, Math.round(Number(value) || 0));
  if (amount >= 100000000) {
    const eok = amount / 100000000;
    return `${Number.isInteger(eok) ? eok.toLocaleString("ko-KR") : eok.toLocaleString("ko-KR", { maximumFractionDigits: 1 })}억원`;
  }
  if (amount >= 10000) {
    const man = amount / 10000;
    return `${Number.isInteger(man) ? man.toLocaleString("ko-KR") : man.toLocaleString("ko-KR", { maximumFractionDigits: 1 })}만원`;
  }
  return money(amount);
}

function yesNo(value: boolean) {
  return value ? "가능" : "불가";
}

function analysisStatusLabel(status: AttachmentAnalysisStatus) {
  const labels: Record<AttachmentAnalysisStatus, string> = {
    uploaded: "업로드됨",
    analyzing: "분석 중",
    analyzed: "분석 완료",
    failed: "분석 실패",
  };
  return labels[status];
}

function countBy<T>(items: T[], getter: (item: T) => string) {
  const counts = items.reduce<Record<string, number>>((acc, item) => {
    const label = getter(item) || "미입력";
    acc[label] = (acc[label] ?? 0) + 1;
    return acc;
  }, {});

  return Object.entries(counts)
    .map(([label, value]) => ({ label, value }))
    .sort((a, b) => b.value - a.value)
    .slice(0, 6);
}

function dealGroup(status: DealStatus) {
  if (["pending_confirmation", "confirmed", "preparing", "delivering", "delivered"].includes(status)) return "진행 중";
  if (status === "completed" || status === "closed") return "완료";
  if (status.includes("cancelled")) return "취소";
  if (status === "disputed") return "문제 발생";
  return dealStatusLabels[status];
}

function attachmentTypeLabel(type: AttachmentType) {
  const labels: Record<AttachmentType, string> = {
    invoice: "거래명세서",
    receipt: "영수증",
    delivery_note: "납품서",
    tax_invoice: "세금계산서",
    photo: "납품 사진",
    etc: "기타",
  };
  return labels[type];
}

function uploadedByLabel(role: "buyer" | "supplier" | "admin") {
  return role === "buyer" ? "구매자" : role === "supplier" ? "공급업체" : "관리자";
}

